(globalThis.TURBOPACK||(globalThis.TURBOPACK=[])).push(["object"==typeof document?document.currentScript:void 0,95340,e=>{"use strict";let a=[...e.i(99508).TREKS,{slug:"pikey-peak",name:"Pikey Peak",region:"Khumbu",category:"trek",days:5,difficulty:"moderate",maxAltitude:4065,distanceKm:55,bestMonths:"Mar–May · Oct–Dec",permits:[{name:"Solududhkunda municipality fee",npr:2e3}],priceMode:"from",priceFromNpr:52e3,summary:"Edmund Hillary called this his favourite view of Everest: a five day ridge walk through lower Solu's Sherpa villages, far below the crowds. From the 4,065 m summit the horizon runs from Dhaulagiri to Kanchenjunga.",whatThisIsNot:"This is not the Khumbu of the postcards: you see Everest from a distance, and that distance is the whole charm.",meetPoint:"Dhap Bazaar roadhead (jeep from Kathmandu)",teahouses:!0,safetyNote:"The summit morning starts near 3,900 m: altitude symptoms are possible even on a short trek, and the dawn wind is bitter. Walk up slowly.",fitnessNote:"Five to six hour days on good trails; any hill-fit walker can manage it.",operatorId:"op-khumbu",palette:"dawn"},{slug:"everest-three-passes",name:"Everest Three Passes",region:"Khumbu",category:"trek",days:18,difficulty:"strenuous",maxAltitude:5535,distanceKm:160,bestMonths:"Mar–May · Oct–Nov",permits:[{name:"Sagarmatha National Park entry",npr:3e3},{name:"Khumbu Pasang Lhamu municipality fee",npr:2e3}],priceMode:"from",priceFromNpr:255e3,summary:"Three passes stitch the Imja, Khumbu and Gokyo valleys into a single high circuit of the Everest region. You still collect Base Camp and the Gokyo lakes, then drop away from the crowds over the Renjo La.",whatThisIsNot:"This is not Base Camp plus a little extra: each pass is its own pre-dawn effort, and the Cho La adds a glacier crossing that turns slow and icy after fresh snow.",meetPoint:"Lukla airstrip",teahouses:!0,safetyNote:"Kongma La, Cho La and Renjo La all top 5,300 metres, with long exposed days between escape routes; acclimatisation nights in Chhukung and Dzongla are built in, and any pass can be bypassed down-valley if symptoms build.",fitnessNote:"You need genuine mountain fitness: back-to-back seven to nine hour days over scree and glacier, three of them starting before dawn.",operatorId:"op-khumbu",palette:"alpenglow"},{slug:"everest-view",name:"Everest View Trek",region:"Khumbu",category:"trek",days:5,difficulty:"moderate",maxAltitude:3880,distanceKm:52,bestMonths:"Mar–May · Oct–Dec",permits:[{name:"Sagarmatha National Park entry",npr:3e3},{name:"Khumbu Pasang Lhamu municipality fee",npr:2e3}],priceMode:"from",priceFromNpr:78e3,summary:"The shortest honest look at Everest: up the Namche hill, tea on the Everest View Hotel terrace, the green roofs of Khumjung on the loop home. Everest, Lhotse and Ama Dablam hold the skyline while your kettle boils.",whatThisIsNot:"This is not a wilderness walk: the trail to Namche is the Khumbu's main street, and Lukla flights can wobble at both ends of a short itinerary.",meetPoint:"Lukla airstrip",teahouses:!0,safetyNote:"Short does not mean low: you sleep near 3,500 metres and day-walk higher, so headaches are common; walk slowly and drink more than feels necessary.",fitnessNote:"The Namche hill is a solid two hour climb; the rest suits any regular walker.",operatorId:"op-khumbu",palette:"day"},{slug:"ebc-via-salleri",name:"EBC via Salleri",region:"Khumbu",category:"trek",days:16,difficulty:"demanding",maxAltitude:5545,distanceKm:185,bestMonths:"Mar–May · Oct–Nov",permits:[{name:"Sagarmatha National Park entry",npr:3e3},{name:"Khumbu Pasang Lhamu municipality fee",npr:2e3}],priceMode:"from",priceFromNpr:192e3,summary:"The pre-airstrip approach to Everest: jeep to Salleri, then ridge after ridge past Taksindu's monastery and the low crossing of the Dudh Koshi before the Khumbu begins. You reach Base Camp acclimatised the old way, on foot from the mid-hills.",whatThisIsNot:"This is not the quick way in: the jeep from Kathmandu is a ten hour grind on rough track, and the first ridges undo their height gains with long hot descents.",meetPoint:"Salleri bazaar (jeep from Kathmandu)",teahouses:!0,safetyNote:"The long walk-in acclimatises you better than flying to Lukla, but the top of the route is unchanged: nights near 5,000 metres, hard cold, and daily oximeter checks with your guide.",fitnessNote:"Expect day after day of big climbs and descents in the mid-hills before the altitude even starts; train for repetition, not speed.",operatorId:"op-khumbu",palette:"forest"},{slug:"dudh-kunda",name:"Dudh Kunda",region:"Khumbu",category:"trek",days:7,difficulty:"moderate",maxAltitude:4560,distanceKm:68,bestMonths:"Apr–May · Oct–Nov",permits:[{name:"Solududhkunda municipality fee",npr:2e3}],priceMode:"from",priceFromNpr:76e3,summary:"The sacred milk lake below Numbur, the peak Solu Sherpas call their valley god, reached through yak pastures above Phaplu. At the August full moon of Janai Purnima, pilgrims come to bathe; most other weeks the shore is yours.",whatThisIsNot:"This is not polished teahouse country: the highest lodges are seasonal herders' shelters, and mist can sit on the lake for a day at a time.",meetPoint:"Phaplu bazaar (jeep from Kathmandu)",teahouses:!0,safetyNote:"You sleep well above 4,000 metres near the lake after a fast rise from the valley; keep the rest day, and treat a worsening headache as a reason to descend.",fitnessNote:"Steady mid-hills walking with one long push to the lake; fine for a regular hill walker.",operatorId:"op-khumbu",palette:"lake"},{slug:"ama-dablam-base-camp",name:"Ama Dablam Base Camp",region:"Khumbu",category:"trek",days:10,difficulty:"demanding",maxAltitude:4600,distanceKm:85,bestMonths:"Mar–May · Oct–Nov",permits:[{name:"Sagarmatha National Park entry",npr:3e3},{name:"Khumbu Pasang Lhamu municipality fee",npr:2e3}],priceMode:"from",priceFromNpr:145e3,summary:"Ama Dablam means the mother's necklace, and its base camp meadow is the closest a trekker gets to the Khumbu's most photographed face. In autumn the grass fills with expedition tents and the ridge above with headtorches.",whatThisIsNot:"This is not a quiet corner of the Khumbu: the approach rides the main Everest trail to Pangboche, full teahouses, Lukla delays and all.",meetPoint:"Lukla airstrip",teahouses:!0,safetyNote:"The meadow sits high enough for acute mountain sickness, and the last climb from Pangboche gains height quickly; a spare acclimatisation night in Namche is built in.",fitnessNote:"Comfortable six hour trail days, with one steep and breathless push up to the meadow itself.",operatorId:"op-khumbu",palette:"dusk"},{slug:"annapurna-base-camp",name:"Annapurna Base Camp",nameNe:"अन्नपूर्ण आधार शिविर",region:"Annapurna",category:"trek",days:7,difficulty:"demanding",maxAltitude:4130,distanceKm:74,bestMonths:"Mar–May · Oct–Nov",permits:[{name:"Annapurna Conservation Area permit",npr:3e3},{name:"TIMS card",npr:2e3}],priceMode:"from",priceFromNpr:78e3,meetPoint:"Nayapul roadhead, Pokhara",whatThisIsNot:"This is not a solitude trek: in high season the Sanctuary lodges fill by mid afternoon and dinner is elbow to elbow.",operatorId:"op-annapurna",summary:"You walk up one gorge for days and the mountains close in behind you: past Machhapuchhre Base Camp the Sanctuary opens, a ring of ice with a single doorway. Sunrise on the south face of Annapurna I is worth every stone step.",story:"No trek in Nepal packs a bigger reward into a single week. From the Modi Khola roadhead you climb one gorge for days: Chhomrong's endless stone staircase, bamboo and spring rhododendron, the river always somewhere below and the walls slowly closing in behind you. Past Machhapuchhre Base Camp the valley simply ends and the Annapurna Sanctuary opens, a full ring of ice with one narrow doorway, seven- and eight-thousand-metre peaks standing shoulder to shoulder around a single glacial floor. You sleep at 4,130 m under the unclimbed Fishtail, wake for sunrise on the south face of Annapurna I, then walk out light-legged to the hot springs at Jhinu Danda.",highlights:["Sunrise on the south face of Annapurna I (8,091 m) from the Sanctuary floor","The Annapurna Sanctuary: a full amphitheatre of ice with one narrow gateway","Machhapuchhre, the sacred unclimbed Fishtail, close overhead at Base Camp","The Modi Khola gorge: Chhomrong's stairs, bamboo forest, spring rhododendron","Hot springs at Jhinu Danda to soak the descent out of your legs"],profile:[{day:1,m:2170,label:"Chhomrong"},{day:2,m:2310,label:"Bamboo"},{day:3,m:3230,label:"Deurali"},{day:3.5,m:3700,label:"Machhapuchhre BC"},{day:4,m:4130,label:"Annapurna BC"},{day:5,m:2310,label:"Bamboo"},{day:6,m:1780,label:"Jhinu Danda"},{day:7,m:822,label:"Pokhara"}],itinerary:[{day:1,title:"Drive Pokhara → Siwai, trek to Chhomrong",km:9,hours:"5–6 h",sleepAltitude:2170,note:"A rough road past Nayapul and Birethanti drops you at the Siwai roadhead; from there the trail climbs the Modi Khola to Jhinu and up Chhomrong's long stone staircase. A tough finish for a first day."},{day:2,title:"Chhomrong → Bamboo",km:11,hours:"5–6 h",sleepAltitude:2310,note:"Down to the river and up through Sinuwa, then a forest descent into Bamboo. The gorge narrows and the big peaks vanish behind its walls."},{day:3,title:"Bamboo → Deurali",km:13,hours:"5–6 h",sleepAltitude:3230,note:"A steady climb through Dovan and Himalaya, waterfalls and mossy forest giving way to the open upper valley. Take lodge advice on the snow above from here."},{day:4,title:"Deurali → Machhapuchhre BC → Annapurna Base Camp",km:10,hours:"6–7 h",sleepAltitude:4130,note:"The Sanctuary day: through the avalanche-prone narrows to MBC (3,700 m), then a gentler last pull onto the glacial floor at ABC (4,130 m). The Fishtail overhead and the whole ring around you."},{day:5,title:"Annapurna Base Camp sunrise → Bamboo",km:16,hours:"6–7 h",sleepAltitude:2310,note:"Up in the cold for first light on Annapurna I, then a long, knee-testing descent all the way back down the gorge to Bamboo."},{day:6,title:"Bamboo → Jhinu Danda",km:12,hours:"5–6 h",sleepAltitude:1780,note:"Back over the Chhomrong steps one last time, then down to the hot springs at Jhinu Danda beside the Modi Khola. Earn the soak."},{day:7,title:"Jhinu → Siwai, drive to Pokhara",km:6,hours:"2–3 h + drive",sleepAltitude:822,note:"A short riverside walk to the Siwai roadhead, then the jeep back to Lakeside for a hot shower and a bigger dinner."}],route:[{lat:28.406,lng:83.816,label:"Chhomrong"},{lat:28.47,lng:83.865,label:"Bamboo"},{lat:28.512,lng:83.878,label:"Deurali"},{lat:28.52,lng:83.882,label:"Machhapuchhre BC"},{lat:28.53,lng:83.878,label:"Annapurna BC"}],teahouses:!0,safetyNote:"The gorge between Deurali and Machhapuchhre Base Camp crosses avalanche chutes that run in winter and early spring: take lodge advice before committing, and move through early in the day.",fitnessNote:"The valley is one long staircase: Chhomrong's stone steps come twice, and most days run six hours. Sound knees and honest fitness required.",palette:"alpenglow",rating:4.9,reviews:396,fairnessDeltaPct:-7,kitSlug:"annapurna-kit"},{slug:"mohare-danda",name:"Mohare Danda",region:"Annapurna",category:"trek",days:5,difficulty:"moderate",maxAltitude:3300,distanceKm:48,bestMonths:"Mar–May · Oct–Dec",permits:[{name:"Annapurna Conservation Area permit",npr:3e3},{name:"TIMS card",npr:2e3}],priceMode:"from",priceFromNpr:48e3,summary:"The community lodge answer to Poon Hill: Magar villages, oak and rhododendron forest, and a summit ridge with Dhaulagiri filling the western sky. Lodge income stays in Nangi and the villages that built and run the trail.",whatThisIsNot:"This is not polished teahouse country: rooms are simple community buildings, menus are short, and hot water arrives by the bucket.",meetPoint:"Galeshwor roadhead, Beni",teahouses:!0,safetyNote:"The open ridge above Nangi draws spring thunderstorms: start walking early and be off the high ground by early afternoon.",fitnessNote:"Steady climbing on village trails, five hour days at most: a strong first trek for regular walkers.",operatorId:"op-annapurna",palette:"dawn"},{slug:"tilicho-lake",name:"Tilicho Lake",region:"Annapurna",category:"trek",days:9,difficulty:"strenuous",maxAltitude:4919,distanceKm:84,bestMonths:"Apr–May · Oct–Nov",permits:[{name:"Annapurna Conservation Area permit",npr:3e3},{name:"TIMS card",npr:2e3}],priceMode:"from",priceFromNpr:112e3,summary:"A turquoise sheet held high by the Grande Barriere, the ice wall Herzog's 1950 expedition failed to find a way across. The walk in through Manang's dry canyon country is nearly as good as the lake.",whatThisIsNot:"This is not a casual side trip off the Circuit: the final approach crosses live scree above a long drop, and turnaround days for wind and snow are normal.",meetPoint:"Besisahar jeep stand",teahouses:!0,safetyNote:"The traverse between Khangsar and Tilicho Base Camp crosses an active landslide zone: your guide will time it for early morning, before the wind picks up and stones start to move.",fitnessNote:"Strenuous: consecutive nights above 4,000 m and a long, cold lake day. Arrive acclimatised or add rest days in Manang.",operatorId:"op-annapurna",palette:"lake"},{slug:"nar-phu-valley",name:"Nar Phu Valley",region:"Annapurna",category:"trek",days:10,difficulty:"demanding",maxAltitude:5320,distanceKm:100,bestMonths:"Apr–May · Sep–Oct",permits:[{name:"Annapurna Conservation Area permit",npr:3e3},{name:"Nar Phu restricted area permit (1 week)",npr:13500}],priceMode:"from",priceFromNpr:145e3,summary:"Two walled villages of stone and prayer flags up a slot canyon most Circuit trekkers stride straight past. Nar and Phu kept their Tibetan speech, yak herds and gompas because for decades almost nobody was allowed in.",whatThisIsNot:"This is not a comfort itinerary: Phu's lodges are basic, nights are cold in every season, and the Kang La is a committing pass day with no easy bail out.",meetPoint:"Koto checkpoint, Manang road",teahouses:!0,safetyNote:"The Kang La is crossed before dawn from Nar: snow can shut it in either shoulder season, and the descent to Ngawal is long, steep and loose.",fitnessNote:"Demanding: sustained walking above 3,500 m for a week and one pass day above 5,000 m. Altitude experience counts for more than gym fitness here.",operatorId:"op-expedition",badges:["restricted"],palette:"dusk"},{slug:"royal-trek",name:"Royal Trek",region:"Annapurna",category:"trek",days:4,difficulty:"easy",maxAltitude:1730,distanceKm:35,bestMonths:"Oct–Mar",permits:[{name:"Annapurna Conservation Area permit",npr:3e3},{name:"TIMS card",npr:2e3}],priceMode:"from",priceFromNpr:34e3,summary:"The low ridge east of Pokhara took its name from Prince Charles's 1981 walk, and the rice terraces have barely changed since. Gurung villages, mustard fields, the Annapurnas across the valley, and Begnas Lake to finish.",whatThisIsNot:"This is not a mountain trek: the ridge stays low, phone signal follows you everywhere, and new farm roads cut across the old trail in places.",meetPoint:"Bijayapur roadhead, Pokhara",teahouses:!0,safetyNote:"Heat is the hazard here, not altitude: carry more water than feels necessary and start walking at first light outside the winter months.",fitnessNote:"Short days on farm paths and gentle steps: comfortable for anyone who walks regularly, and a good first trek with children.",operatorId:"op-annapurna",palette:"day"},{slug:"panchase",name:"Panchase",region:"Annapurna",category:"trek",days:4,difficulty:"easy",maxAltitude:2500,distanceKm:38,bestMonths:"Oct–Apr",permits:[{name:"Annapurna Conservation Area permit",npr:3e3},{name:"TIMS card",npr:2e3}],priceMode:"from",priceFromNpr:36e3,summary:"A forest ridge that rises straight from Phewa Lake to a summit shrine shared by Hindu and Buddhist pilgrims. Orchids in the mossy oak, and a skyline that runs from Dhaulagiri to Manaslu.",whatThisIsNot:"This is not wilderness: mule paths and village homestays thread the whole ridge, and Pokhara's lights glow below you after dark.",meetPoint:"Pame roadhead, Phewa lakeside",teahouses:!0,safetyNote:"Leeches own the forest in the wet months and mist can shut the views by mid morning: start early, and stay on the main ridge path when cloud comes in.",fitnessNote:"Gentle days with one sustained stair climb to the summit shrine: manageable for any regular walker.",operatorId:"op-annapurna",palette:"forest"},{slug:"sikles-eco-trail",name:"Sikles Eco Trail",region:"Annapurna",category:"trek",days:5,difficulty:"moderate",maxAltitude:2e3,distanceKm:44,bestMonths:"Mar–May · Oct–Dec",permits:[{name:"Annapurna Conservation Area permit",npr:3e3},{name:"TIMS card",npr:2e3}],priceMode:"from",priceFromNpr:46e3,summary:"Slate roofs and terraced millet directly under the wall of Annapurna II: Sikles is one of Nepal's largest Gurung villages and an early model for community-run tourism. The walking is farm country above the Madi Khola.",whatThisIsNot:"This is not a high route: the reward is village life under big peaks, not passes, and the new jeep road now reaches Sikles itself.",meetPoint:"Kalikasthan roadhead, Begnas",teahouses:!0,safetyNote:"Stone staircases turn greasy in rain and the Madi valley holds afternoon heat in spring: poles for the long descents, water for the climbs.",fitnessNote:"Moderate: five hour days with long stepped climbs between villages. Regular hill walkers will not struggle.",operatorId:"op-annapurna",palette:"day"},{slug:"kapuche-glacier-lake",name:"Kapuche Glacier Lake",region:"Annapurna",category:"trek",days:4,difficulty:"moderate",maxAltitude:2546,distanceKm:28,bestMonths:"Oct–Apr",permits:[{name:"Annapurna Conservation Area permit",npr:3e3},{name:"TIMS card",npr:2e3}],priceMode:"from",priceFromNpr:4e4,summary:"Nepal's lowest glacier lake, a green pool in a stone cirque where avalanches off Annapurna II rumble across the water all afternoon. You walk in from Sikles on herders' trails along the Madi Khola.",whatThisIsNot:"This is not a polished lodge route: beyond Sikles the stops are herders' shelters turned simple teahouses, and landslide scars cross the trail.",meetPoint:"Sikles jeep stand",teahouses:!0,safetyNote:"Watch the avalanche fans from the viewpoint above the lake, never from the shoreline beneath them, and expect the upper trail to shift a little after every monsoon.",fitnessNote:"Moderate: valley walking rather than big climbs, but the days are long and the ground uneven. Sure footing matters more than lungs here.",operatorId:"op-annapurna",palette:"lake"},{slug:"australian-camp-dhampus",name:"Australian Camp and Dhampus",region:"Annapurna",category:"trek",days:2,difficulty:"easy",maxAltitude:2100,distanceKm:12,bestMonths:"Oct–Apr",permits:[{name:"Annapurna Conservation Area permit",npr:3e3},{name:"TIMS card",npr:2e3}],priceMode:"from",priceFromNpr:16e3,summary:"An hour above the Kande road, the grass shelf of Australian Camp faces the whole Annapurna wall: Machhapuchhre, Annapurna South, Mardi. Stay the night for the dawn colour, then walk out through Dhampus village.",whatThisIsNot:"This is not remote: day walkers and picnic groups share the meadow, and the quiet only arrives once the last jeep has left Kande.",meetPoint:"Kande roadhead, Pokhara",teahouses:!0,safetyNote:"Easy ground, but the stone steps from Dhampus down to Phedi are slick after rain, and spring haze can hide the peaks by mid morning: sleep up there for the dawn.",fitnessNote:"Two short walking days on good paths: anyone who can climb stairs for an hour can manage it.",operatorId:"op-annapurna",palette:"alpenglow"},{slug:"gosainkunda-lakes",name:"Gosainkunda Lakes",region:"Langtang",category:"trek",days:6,difficulty:"demanding",maxAltitude:4610,distanceKm:52,bestMonths:"Mar–May · Oct–Nov",permits:[{name:"Langtang National Park entry",npr:3e3},{name:"TIMS card",npr:2e3}],priceMode:"from",priceFromNpr:68e3,summary:"Shiva is said to have struck his trident into the mountain here and drunk the water to cool the poison in his throat. Each August full moon, Janai Purnima pilgrims climb from Dhunche in their thousands to bathe in the lake.",whatThisIsNot:"This is not a soft lakes-and-meadows walk: the climb above Lauribina is relentless, and the lakes are cold, austere places of stone, ice and prayer flags.",meetPoint:"Dhunche bazaar",teahouses:!0,safetyNote:"The trail rises from Dhunche near 2,000 m to the 4,600 m Lauribina La in three walking days: that rapid gain makes altitude sickness the real hazard. Sleep at Sing Gompa on the way up, and descend if symptoms build overnight.",fitnessNote:"Six hour days with sustained climbing above 3,000 m; you need recent hill fitness and the patience to walk slowly.",operatorId:"op-langtang",palette:"lake"},{slug:"helambu-circuit",name:"Helambu Circuit",region:"Langtang",category:"trek",days:5,difficulty:"moderate",maxAltitude:3640,distanceKm:60,bestMonths:"Mar–May · Oct–Dec",permits:[{name:"Shivapuri Nagarjun National Park entry",npr:1e3},{name:"Langtang National Park entry",npr:3e3},{name:"TIMS card",npr:2e3}],priceMode:"from",priceFromNpr:48e3,summary:"Kathmandu's nearest trekking country: from the water-pipeline steps at Sundarijal you climb within a day into Hyolmo villages, hilltop gompas and rhododendron forest. From Tharepati's ridge the snow line runs from Langtang Lirung across to Dorje Lakpa.",whatThisIsNot:"This is not remote country: being a day from Kathmandu means the trail crosses new roads more than once, and you share the first morning with day-trippers bound for Chisapani.",meetPoint:"Sundarijal roadhead, Kathmandu",teahouses:!0,safetyNote:"Altitude is modest, but the stone-step descents are long on the knees and the ridge between Kutumsang and Tharepati carries little water in spring: fill up at the village taps before you leave.",fitnessNote:"Five to six hour days that repeatedly climb and drop between ridge and river; the circuit suits any regular hill walker.",operatorId:"op-langtang",palette:"forest"},{slug:"tamang-heritage-trail",name:"Tamang Heritage Trail",region:"Langtang",category:"trek",days:5,difficulty:"moderate",maxAltitude:3165,distanceKm:52,bestMonths:"Mar–May · Oct–Nov",permits:[{name:"Langtang National Park entry",npr:3e3},{name:"TIMS card",npr:2e3}],priceMode:"from",priceFromNpr:52e3,summary:"A loop through Tamang villages on the hills facing Tibet: shingle-roofed Gatlang, the herders' pastures at Nagthali, and homestay kitchens where dinner cooks over the family fire. At Tatopani you soak trail-sore legs in the hot spring pools.",whatThisIsNot:"This is not backcountry: the trade road to the Rasuwagadhi border post runs along the valley floor below, and short road sections link several of the villages.",meetPoint:"Syabrubesi bus park",teahouses:!0,safetyNote:"Altitude stays moderate, but winter snowfall can close the Nagthali ridge for days at a time: outside the main seasons, ask in Thuman about conditions before committing to the high loop.",fitnessNote:"Four to six hour days on village trails with one long climb to Nagthali; comfortable for anyone who walks regularly.",operatorId:"op-langtang",palette:"dusk"},{slug:"ganja-la-pass",name:"Ganja La Pass",region:"Langtang",category:"trek",days:8,difficulty:"strenuous",maxAltitude:5130,distanceKm:76,bestMonths:"Apr–May · Oct–Nov",permits:[{name:"Langtang National Park entry",npr:3e3},{name:"TIMS card",npr:2e3}],priceMode:"from",priceFromNpr:128e3,summary:"The hard way out of Langtang: beyond Kyanjin Gompa the lodges stop, and you climb with tents and a fixed rope to the snow notch of the pass, then descend through two days of empty yak pastures to Tarke Gyang in Helambu.",whatThisIsNot:"This is not a teahouse trek with one big day: beyond Kyanjin there are no lodges, no rescue posts and often no other parties, and fresh snow on the pass can turn the whole trip around.",meetPoint:"Syabrubesi bus park",teahouses:!1,safetyNote:"The final approach to the pass is steep snow and loose rock where the crew fixes a rope, and the high camp sits above 4,800 m. Between Kyanjin and Tarke Gyang there is no teahouse or rescue post: the guide's weather call is final.",fitnessNote:"Seven to nine hour days carrying altitude and cold, with a pre-dawn crossing; you need genuine mountain fitness and steady feet on snow.",operatorId:"op-langtang",palette:"alpenglow"},{slug:"panch-pokhari",name:"Panch Pokhari",region:"Langtang",category:"trek",days:6,difficulty:"demanding",maxAltitude:4100,distanceKm:54,bestMonths:"Apr–May · Sep–Nov",permits:[{name:"Langtang National Park entry",npr:3e3},{name:"TIMS card",npr:2e3}],priceMode:"from",priceFromNpr:84e3,summary:"Five lakes in a stone bowl at the head of the Indrawati river: a pilgrimage site where jhankri shamans drum through the Janai Purnima full moon each August. For the rest of the year you may have the shrine and its prayer flags to yourselves.",whatThisIsNot:"This is not a lodge trek: beyond the last village the shelters are bare pilgrim huts, so the honest way to walk it is supported camping with tents and a cook.",meetPoint:"Bhotang roadhead, Sindhupalchok",teahouses:!1,safetyNote:"You gain around 2,500 m from the roadhead in three days, and storms build quickly off the Jugal peaks: keep a spare day in hand, and descend if altitude symptoms worsen overnight.",fitnessNote:"Six to seven hour days on rough, lightly maintained trails with steady height gain; best for walkers with a previous trek behind them.",operatorId:"op-langtang",palette:"dawn"},{slug:"tsum-valley",name:"Tsum Valley",region:"Manaslu",category:"trek",days:10,difficulty:"demanding",maxAltitude:3700,distanceKm:102,bestMonths:"Mar–May · Oct–Nov",permits:[{name:"Tsum Valley restricted area permit (8 days)",npr:5400},{name:"Manaslu Conservation Area permit",npr:3e3},{name:"Annapurna Conservation Area permit",npr:3e3}],priceMode:"from",priceFromNpr:148e3,summary:"Closed to outsiders until 2008, Tsum still keeps its own law: under the valley's Shyagya decree, killing any animal is forbidden. Mani walls lead up to Mu Gompa while blue sheep graze unbothered above Nile village.",whatThisIsNot:"This is not a turn-up-and-go trek: the restricted permit needs passport paperwork filed in advance and a minimum group of two trekkers with a registered guide.",meetPoint:"Machha Khola roadhead",teahouses:!0,safetyNote:"Beyond Lokpa the valley has no road and only basic health posts: evacuation is by helicopter. Nights above Chhokangparo drop below freezing from October, and we pace the climb to Mu Gompa to let your body adjust.",fitnessNote:"Demanding: six to seven hour days on stone staircases and exposed gorge trail before the valley opens. Back-to-back hill days are the right preparation.",operatorId:"op-expedition",badges:["restricted"],palette:"alpenglow"},{slug:"ruby-valley",name:"Ruby Valley",region:"Manaslu",category:"trek",days:6,difficulty:"moderate",maxAltitude:3842,distanceKm:62,bestMonths:"Mar–May · Oct–Dec",permits:[{name:"Langtang National Park entry",npr:3e3},{name:"TIMS card",npr:2e3}],priceMode:"from",priceFromNpr:66e3,summary:"A quiet crossing between the Langtang and Ganesh Himal ranges, from Gatlang's stone Tamang houses to the Gurung villages of Tipling and Shertung. The valley takes its name from the rubies once mined near Somdang, below the Pangsang Pass.",whatThisIsNot:"The lodges here are family homes with shared rooms and whatever the household is cooking: warm, but not hotels.",meetPoint:"Syabrubesi bus park",teahouses:!0,safetyNote:"Health posts between Gatlang and Dhading Besi are basic and phone signal is patchy: carry your personal medication. Cloud builds over the Pangsang Pass by late morning, so we cross early.",fitnessNote:"Five to six hour days with one long pull up to the pass; a walker who is comfortable on steep hill paths will manage.",operatorId:"op-langtang",palette:"forest"},{slug:"ganesh-himal-base-camp",name:"Ganesh Himal Base Camp",region:"Manaslu",category:"trek",days:9,difficulty:"demanding",maxAltitude:4200,distanceKm:84,bestMonths:"Mar–May · Oct–Nov",permits:[{name:"Langtang National Park entry",npr:3e3},{name:"TIMS card",npr:2e3}],priceMode:"from",priceFromNpr:118e3,summary:"A supported camp in the yak pastures under Yangra, the highest summit of the Ganesh Himal, due north of Dhading. Above the last houses at Lapa the only traffic is herders moving animals between kharkas.",whatThisIsNot:"This is not a teahouse route: above the villages you sleep in tents our crew carries and pitches, and the nearest hot shower is days behind you.",meetPoint:"Dhading Besi jeep stand",teahouses:!1,safetyNote:"Above Lapa there are no lodges, health posts or phone signal: the crew carries a satellite communicator and a full medical kit. Nights at the upper camps fall below freezing even in October.",fitnessNote:"Demanding: six to seven hour days on herders' trails that fade in and out above the villages. Previous multi-day trekking and a tolerance for tent nights matter more than speed.",operatorId:"op-langtang",palette:"night"},{slug:"lower-mustang-muktinath",name:"Lower Mustang and Muktinath",region:"Mustang",category:"trek",days:5,difficulty:"moderate",maxAltitude:3800,distanceKm:38,bestMonths:"May–Oct",permits:[{name:"Annapurna Conservation Area permit",npr:3e3},{name:"TIMS card",npr:2e3}],priceMode:"from",priceFromNpr:68e3,summary:"The trans-Himalayan desert on easy terms: short walks between Kagbeni's mud-walled alleys, Marpha's apple orchards and the 108 water spouts of Muktinath, with jeep support the whole way. This is rain-shadow country, dry and walkable right through the monsoon.",whatThisIsNot:"This is not a wilderness walk: the Beni to Jomsom road runs through the valley and jeeps share stretches of your trail.",meetPoint:"Jomsom airstrip",teahouses:!0,safetyNote:"Gaining height quickly is the risk here: Muktinath sits well above Jomsom and headaches are common on day one. The Kali Gandaki wind rises hard by late morning; we walk early.",fitnessNote:"Three to four hour walking days on jeep track and village trail; comfortable for any regular walker.",operatorId:"op-annapurna",palette:"dusk"},{slug:"damodar-kunda",name:"Damodar Kunda",region:"Mustang",category:"trek",days:12,difficulty:"strenuous",maxAltitude:5100,distanceKm:140,bestMonths:"May–Oct",permits:[{name:"Upper Mustang restricted area permit (10 days)",npr:67500},{name:"Annapurna Conservation Area permit",npr:3e3}],priceMode:"from",priceFromNpr:285e3,summary:"Beyond the villages of Upper Mustang, three sacred lakes lie in a bowl of scree where Hindu pilgrims gather at Janai Purnima each August. The approach passes the cave monastery of Luri Gompa and some of the emptiest country in Nepal.",whatThisIsNot:"This is not a teahouse route: beyond Luri Gompa there are no lodges, no shops and no phone signal, only what the mule train carries.",meetPoint:"Jomsom airstrip",teahouses:!1,safetyNote:"High camps are cold even in midsummer and the nearest help is days away: acclimatisation is written into the route, not optional. The restricted permit requires a registered guide and full camping crew, both included.",fitnessNote:"Long walking days at altitude on rough ground; previous trekking above four thousand metres matters more than gym fitness.",operatorId:"op-expedition",badges:["restricted"],palette:"alpenglow"},{slug:"dhaulagiri-circuit",name:"Dhaulagiri Circuit",region:"Dhaulagiri",category:"trek",days:16,difficulty:"strenuous",maxAltitude:5360,distanceKm:150,bestMonths:"Apr–May · Sep–Oct",permits:[{name:"Annapurna Conservation Area permit",npr:3e3},{name:"Dhaulagiri rural municipality fee",npr:2e3}],priceMode:"from",priceFromNpr:265e3,summary:"A full camping expedition around the seventh-highest mountain on earth: up the Myagdi Khola gorge to Dhaulagiri Base Camp, over French Pass into the Hidden Valley, and down to Marpha. No villages for a week, just glacier, moraine and canvas.",whatThisIsNot:"This is not a trek with a safety margin: it is the hardest non-climbing route in this catalogue, with glacier travel, high camps and no lodges or exit roads for days.",meetPoint:"Beni bus park, Myagdi",teahouses:!1,safetyNote:"You sleep above five thousand metres in the Hidden Valley and cross two glaciated passes; the crew carries ropes, a satellite phone and a full medical kit. Weather can pin the team down, so the itinerary holds spare days.",fitnessNote:"The fittest trekkers find this hard: long days on moraine and snow, then cold nights under canvas. Previous experience on a camping trek at altitude is strongly advised.",operatorId:"op-expedition",palette:"night"},{slug:"lower-dolpo-phoksundo",name:"Lower Dolpo and Phoksundo Lake",region:"Dolpo",category:"trek",days:9,difficulty:"demanding",maxAltitude:3611,distanceKm:72,bestMonths:"May–Oct",permits:[{name:"Lower Dolpo restricted area permit (per week)",npr:2700},{name:"Shey Phoksundo National Park entry",npr:3e3}],priceMode:"from",priceFromNpr:168e3,summary:"A short walk into big country: up the Suli Gaad gorge to Phoksundo, Nepal's deepest lake, turquoise under bare cliffs beside the Bon village of Ringmo. Acclimatised parties can extend over the Numa La towards Do Tarap.",whatThisIsNot:"This is not a comfort trek: lodges beyond Chhepka are basic, with mud floors, shared rooms and no heating beyond the kitchen stove.",meetPoint:"Juphal airstrip, Dolpa",teahouses:!0,safetyNote:"Flights out of Juphal are morning-only and frequently lost to wind, so the itinerary keeps a spare day. The restricted permit requires a registered guide and a minimum party of two, both arranged for you.",fitnessNote:"Steady five to six hour days up a river gorge with one long climb to the lake shelf; a fit hill walker will manage.",operatorId:"op-expedition",badges:["restricted"],palette:"lake"},{slug:"upper-dolpo",name:"Upper Dolpo",region:"Dolpo",category:"trek",days:18,difficulty:"strenuous",maxAltitude:5350,distanceKm:186,bestMonths:"May–Oct",permits:[{name:"Upper Dolpo restricted area permit (10 days)",npr:67500},{name:"Shey Phoksundo National Park entry",npr:3e3}],priceMode:"from",priceFromNpr:385e3,summary:"The high desert Peter Matthiessen walked into for The Snow Leopard: over the Kang La to Shey Gompa below Crystal Mountain, then through Saldang's barley terraces on trails that carry more blue sheep than people. Rain shadow keeps it open all monsoon.",whatThisIsNot:"This is not a trek to ease into: nearly three weeks of camping above four thousand metres, days from any road, with no rescue close at hand.",meetPoint:"Juphal airstrip, Dolpa",teahouses:!1,safetyNote:"Helicopter evacuation is the only fast way out and weather can ground it for days; the crew carries a satellite phone and a portable altitude chamber. Acclimatisation is staged before the first pass.",fitnessNote:"Repeated high pass crossings and freezing camp nights over nearly three weeks: come with a previous expedition-style trek behind you.",operatorId:"op-expedition",badges:["restricted"],palette:"night"},{slug:"makalu-base-camp",name:"Makalu Base Camp",region:"Makalu",category:"trek",days:14,difficulty:"strenuous",maxAltitude:4870,distanceKm:130,bestMonths:"Mar–May · Oct–Nov",permits:[{name:"Makalu Barun National Park entry",npr:3e3},{name:"Makalu rural municipality fee",npr:2e3}],priceMode:"from",priceFromNpr:225e3,summary:"Over the Shipton La and down into the Barun valley, where old-growth fir and rhododendron run up against the granite pyramid of the world's fifth-highest mountain. Past the last lodges at Khongma, your crew carries the camp.",whatThisIsNot:"This is not a trek you can shorten: it is long and committing, the Barun weather closes in fast, and once over the Shipton La there is no easy way out but back.",meetPoint:"Tumlingtar airport, then jeep to Num",teahouses:!1,safetyNote:"Beyond Khongma you are camping in a national park with no road and little phone signal; evacuation means a helicopter and a clear morning. The itinerary holds acclimatisation nights below base camp, and your crew carries a comms device.",fitnessNote:"Six to eight hour days, the Shipton La crossed in both directions, and cold nights under canvas: you need genuine hill fitness and previous multi-day trekking at altitude.",operatorId:"op-expedition",palette:"alpenglow"},{slug:"rolwaling-valley",name:"Rolwaling Valley",region:"Rolwaling",category:"trek",days:8,difficulty:"demanding",maxAltitude:4580,distanceKm:68,bestMonths:"Mar–May · Oct–Nov",permits:[{name:"Gaurishankar Conservation Area permit",npr:3e3},{name:"TIMS card",npr:2e3}],priceMode:"from",priceFromNpr:104e3,summary:"A steep-sided Sherpa beyul under the twin summits of Gauri Shankar: river gorge, then Beding's stone houses, then the grey moraine of Tsho Rolpa, Nepal's largest glacial lake. The valley has sent generations of climbing Sherpas to Everest.",whatThisIsNot:"This is not a placid lake walk: Tsho Rolpa is rigged with early-warning sirens because it could burst, and the trail exists partly because the danger does.",meetPoint:"Chhet Chhet roadhead, Dolakha",teahouses:!0,safetyNote:"Altitude arrives fast: the itinerary sleeps at Na before the lake, and turning back is the treatment if symptoms build. Sections of the lower gorge cross old landslide scars, best walked early in the day.",fitnessNote:"Big height gains on rough stone staircases from the first afternoon; five to seven hour days that reward genuine hill fitness.",operatorId:"op-khumbu",palette:"lake"},{slug:"milke-danda-ridge",name:"Milke Danda Ridge",region:"Kanchenjunga",category:"trek",days:6,difficulty:"moderate",maxAltitude:3480,distanceKm:58,bestMonths:"Mar–May · Oct–Nov",permits:[{name:"TIMS card",npr:2e3},{name:"Sankhuwasabha community trail fee",npr:1e3}],priceMode:"from",priceFromNpr:62e3,summary:"This is the ridge between the Arun and the Tamur, walked lodge to lodge through what botanists call Nepal's rhododendron capital, at its reddest in late March and April. From Gupha Pokhari the horizon holds both Makalu and Kanchenjunga.",whatThisIsNot:"This is not a comfort circuit: the community lodges are basic, blankets are thin and the menu rarely strays from dal bhat, so bring a sleeping bag.",meetPoint:"Basantapur roadhead, Tehrathum",teahouses:!0,safetyNote:"Afternoon cloud sits on the crest most days and the lodges are far apart; start early and carry water, because sources on the ridgetop are scarce. Spring thunderstorms build quickly on exposed ground.",fitnessNote:"Four to six hour days of steady, rolling ridge walking; any regular hill walker will manage, though nights near the high point are cold.",operatorId:"op-heritage",palette:"forest"},{slug:"khaptad",name:"Khaptad",region:"Far West",category:"trek",days:6,difficulty:"moderate",maxAltitude:3300,distanceKm:56,bestMonths:"Mar–May · Oct–Nov",permits:[{name:"Khaptad National Park entry",npr:3e3},{name:"TIMS card",npr:2e3}],priceMode:"from",priceFromNpr:88e3,summary:"A rolling plateau of grass moorland and dwarf bamboo where the hermit Khaptad Baba meditated for five decades, and Nepal stops looking like Nepal. Buffalo herders cross the patans between stands of oak while clouds fill the valleys below the rim.",whatThisIsNot:"This is not teahouse country: the far west runs on homestays, park rest houses and tents, not lodge infrastructure, so pack a sleeping bag for the floor at Bichpani.",meetPoint:"Dipayal or Silgadhi bazaar, Doti",teahouses:!1,safetyNote:"Evacuation from the far west is slow: helicopters stage from Dhangadhi or Nepalgunj, weather permitting, and afternoon fog closes over the plateau fast. Keep insurance current and your onward days flexible.",fitnessNote:"Two climbing days of five to six hours from Silgadhi, then gentle plateau walking: any regular hill walker can manage it.",operatorId:"op-west",palette:"forest"},{slug:"api-base-camp",name:"Api Base Camp",region:"Far West",category:"trek",days:9,difficulty:"demanding",maxAltitude:4100,distanceKm:95,bestMonths:"Mar–May · Oct–Nov",permits:[{name:"Api Nampa Conservation Area permit",npr:3e3},{name:"TIMS card",npr:2e3}],priceMode:"from",priceFromNpr:135e3,summary:"The far west's highest mountain rises in one white wall above a valley of stone-roofed villages and walnut trees. You follow the Chameliya river from Ghusa to a base camp meadow beside the small lake of Kali Dhunga.",whatThisIsNot:"This is not a fly-in trek: reaching the roadhead costs a long jeep day beyond Dhangadhi airport, often two, and the same again on the way home.",meetPoint:"Gokuleshwar roadhead, Darchula",teahouses:!1,safetyNote:"There is no rescue post beyond Gokuleshwar, and the upper Chameliya trail crosses landslide slopes that shift each monsoon. Helicopter evacuation stages from Dhangadhi and waits on weather, so insurance with heli cover is required.",fitnessNote:"Six to seven hour days on rough trail with steady altitude gain to base camp; you need to be comfortable camping and walking on consecutive days.",operatorId:"op-west",palette:"alpenglow"},{slug:"humla-limi-valley",name:"Humla Limi Valley",region:"Karnali",category:"trek",days:14,difficulty:"strenuous",maxAltitude:4940,distanceKm:150,bestMonths:"May–Oct",permits:[{name:"Humla restricted area permit (1 week)",npr:6750},{name:"TIMS card",npr:2e3}],priceMode:"from",priceFromNpr:285e3,summary:"The old salt route toward Mount Kailash, through Limi's walled Tibetan villages of Til, Halji and Jang, where the eleventh-century Rinchenling gompa still keeps morning prayers. Beyond the Nyalu La the land turns to bare plateau and blue sheep country.",whatThisIsNot:"This is not a route to improvise: the restricted permit ties you to a registered agency and a fixed itinerary, and past Kermi's hot springs there is no shop and mostly no phone signal until you loop back to Simikot.",meetPoint:"Simikot airstrip, Humla",teahouses:!1,safetyNote:"Simikot flights and any evacuation both wait on weather, sometimes for days, so build slack into onward plans. We carry a satellite phone, and the Nyalu La crossing holds for a clear morning.",fitnessNote:"Strenuous: two weeks of six to eight hour days, camping throughout, with one long, cold pass crossing at the top of the loop. Arrive with genuine back-to-back hill fitness.",operatorId:"op-expedition",badges:["restricted"],palette:"dusk"},{slug:"badimalika",name:"Badimalika",region:"Karnali",category:"trek",days:7,difficulty:"demanding",maxAltitude:4200,distanceKm:68,bestMonths:"May–Jun · Sep–Oct",permits:[{name:"Bajura community trail fee",npr:1e3},{name:"TIMS card",npr:2e3}],priceMode:"from",priceFromNpr:98e3,summary:"In the monsoon shoulder the meadows stand ankle-deep in flowers below the hilltop shrine of Malika Bhagwati, and on the August full moon the Janai Purnima fair brings lines of pilgrims up from Martadi. Outside the fair the ridges belong to shepherds.",whatThisIsNot:"This is not a stroll between lodges: water points sit hours apart on the high meadows, and phone signal drops out a day above Martadi.",meetPoint:"Martadi bazaar, Bajura",teahouses:!1,safetyNote:"Storms build over the open meadows by early afternoon in the fair season, and the only shelter is a shepherd hut, so ridge days start at first light. Evacuation is a weather-dependent helicopter from Nepalgunj.",fitnessNote:"Demanding: long ridge days with two steep pulls near the shrine, and the thin air slows everyone. Train with full-day hikes beforehand.",operatorId:"op-west",palette:"day"},{slug:"chisapani-nagarkot",name:"Chisapani to Nagarkot",region:"Mid-hills",category:"trek",days:3,difficulty:"easy",maxAltitude:2440,distanceKm:36,bestMonths:"Oct–Apr",permits:[{name:"Shivapuri Nagarjun National Park entry",npr:1e3}],priceMode:"from",priceFromNpr:29e3,summary:"Kathmandu's classic rim walk: up the steps beside Sundarijal's old water pipeline, through Shivapuri's oak and rhododendron to Chisapani, then along the valley rim to Nagarkot's sunrise tower. At dawn, Langtang and Dorje Lakpa stand clear across the Helambu hills.",whatThisIsNot:"This is not backcountry: the rim carries dirt roads, mobile signal and school-run motorbikes, and spring haze can reduce the mountains to a rumour.",meetPoint:"Sundarijal roadhead, Kathmandu",teahouses:!0,safetyNote:"Low altitude with lodges each night: the real cares are midday sun, water between villages and short road stretches shared with motorbikes. In monsoon the leeches take over the forest.",fitnessNote:"Four to six hour days on stone steps and ridge paths; a fit first-timer's trek.",operatorId:"op-heritage",palette:"dawn"},{slug:"shivapuri-loop",name:"Shivapuri Loop",region:"Mid-hills",category:"trek",days:2,difficulty:"easy",maxAltitude:2732,distanceKm:16,bestMonths:"Oct–Apr",permits:[{name:"Shivapuri Nagarjun National Park entry",npr:1e3}],priceMode:"from",priceFromNpr:19e3,summary:"Kathmandu's forest summit, an hour from the ring road. Climb past the Nagi Gumba nunnery to Baghdwar, where the Bagmati begins at a stone tiger's mouth, then take the stepped summit early, before the haze rises.",whatThisIsNot:"This is not a viewpoint peak: the summit sits in old oak and rhododendron, and the reward is birdsong, spring water and wild forest pressed against a capital city.",meetPoint:"Budhanilkantha gate, Kathmandu",teahouses:!0,safetyNote:"Most of the climb is stone staircase, harder on the knees coming down, and in monsoon the leeches are relentless. Carry water; the army post at the gate logs walkers in and out.",fitnessNote:"A sustained 1,200 m of ascent split across the overnight; steady walkers need no training.",operatorId:"op-heritage",palette:"forest"},{slug:"champadevi",name:"Champadevi",region:"Mid-hills",category:"trek",days:1,difficulty:"easy",maxAltitude:2278,distanceKm:9,bestMonths:"Oct–Apr",permits:[],priceMode:"from",priceFromNpr:9500,summary:"The gentlest of the valley's rim peaks: a morning's climb through resin-scented pine above Pharping's Tibetan monasteries to a summit shared by a Buddhist stupa and a Hindu shrine. On clear winter mornings the range runs from Ganesh Himal to Gauri Shankar.",whatThisIsNot:"This is not solitude on Saturdays: Champadevi is Kathmandu's picnic hill, and by late morning the haze usually folds the snow peaks back into the sky.",meetPoint:"Pharping bazaar",teahouses:!0,safetyNote:"One steady hour of steps, then open ridge: sun and dehydration are the risks here, not altitude. Start at dawn for the view and the cool.",fitnessNote:"Two to three hours up from Pharping and less back down; fine for anyone who walks regularly.",operatorId:"op-heritage",palette:"day"},{slug:"balthali-village",name:"Balthali Village",region:"Mid-hills",category:"trek",days:2,difficulty:"easy",maxAltitude:1730,distanceKm:14,bestMonths:"Oct–Apr",permits:[],priceMode:"from",priceFromNpr:18500,summary:"Farm Nepal at walking pace: from Panauti's temple squares, field paths cross the Roshi Khola into mustard and rice terraces, climbing at last to Balthali's plateau above the valley. Newar and Tamang farmsteads, threshing floors and school bells fill the day.",whatThisIsNot:"This is not a mountain trek: the snow peaks are a thin white line on the northern horizon, and tractors and motorbikes share the village lanes you walk.",meetPoint:"Panauti bus park",teahouses:!0,safetyNote:"Low and warm: sun is the main concern, and the clay paths turn slick after rain. In monsoon expect leeches on the shaded stretches.",fitnessNote:"Three to four gentle hours a day on farm paths; fine for families and first walks.",operatorId:"op-heritage",palette:"dusk"},{slug:"dhulikhel-namobuddha",name:"Dhulikhel to Namobuddha",region:"Mid-hills",category:"trek",days:2,difficulty:"easy",maxAltitude:1982,distanceKm:19,bestMonths:"Oct–Apr",permits:[],priceMode:"from",priceFromNpr:19500,summary:"An old pilgrim route: from Dhulikhel's carved Newar lanes over the Kali temple ridge to Namobuddha, the stupa marking where, in legend, the Buddha gave his body to a starving tigress. Sleep near Thrangu monastery and wake to horns at morning puja.",whatThisIsNot:"This is not a remote shrine: a road runs all the way to the stupa, and pilgrim buses, school runs and village dogs share the quieter lanes with you.",meetPoint:"Dhulikhel bus park",teahouses:!0,safetyNote:"Short sections follow the motor road, so watch for jeeps on blind bends; beyond that the cares are sun and afternoon haze rather than terrain.",fitnessNote:"Four hour days with one steady climb out of Dhulikhel; comfortable for any regular walker.",operatorId:"op-heritage",palette:"dawn"},{slug:"sailung",name:"Sailung",region:"Mid-hills",category:"trek",days:3,difficulty:"moderate",maxAltitude:3146,distanceKm:30,bestMonths:"Mar–May · Oct–Nov",permits:[],priceMode:"from",priceFromNpr:34e3,summary:"The hundred-hill viewpoint of Dolakha: from Sailung's grass summit, ridgelines fall away on every side while Gauri Shankar holds the northern skyline. Between the meadows this is bombo country, Tamang villages where shamans still drum at the full-moon gatherings.",whatThisIsNot:"This is not a lodge circuit: nights are village homestays with shared rooms and dal bhat twice a day, and the jeep ride out from Kathmandu is longer than any day's walk.",meetPoint:"Mude bazaar, Dolakha",teahouses:!0,safetyNote:"The summit meadow tops 3,000 m: nights are cold in every season and spring afternoons build thunderstorms, so walk the high ridge in the morning.",fitnessNote:"Five hour days with one long climb to the ridge; a step up from a valley-rim stroll, but within reach of any regular hill walker.",operatorId:"op-heritage",palette:"alpenglow"},{slug:"island-peak",name:"Island Peak",region:"Khumbu",category:"peak",days:16,difficulty:"strenuous",maxAltitude:6189,distanceKm:110,bestMonths:"Apr–May · Oct–Nov",permits:[{name:"NMA climbing permit (spring rate)",npr:33750},{name:"Sagarmatha National Park entry",npr:3e3}],priceMode:"from",priceFromNpr:185e3,summary:"Imja Tse stands inside a ring of walls, with Lhotse's south face filling the sky behind the summit ridge. The route crosses the summit glacier on ladders laid over open crevasses before the fixed lines up the headwall.",whatThisIsNot:"This is not a trek with a summit bolted on: above high camp it is glaciated mountaineering on crampons, rope and ladders, run with a registered expedition partner.",meetPoint:"Lukla airstrip",teahouses:!1,safetyNote:"Summit day starts in the dark and the crux is real: ladder crossings over crevasses, then fixed lines on a steep headwall in serious cold. The EBC-side approach builds acclimatisation, and it is non-negotiable.",fitnessNote:"Prior high-altitude trekking expected: you should have been comfortable near 5,000 m before, with the legs for a ten hour summit day.",operatorId:"op-expedition",badges:["expedition-partner"],palette:"alpenglow"},{slug:"mera-peak",name:"Mera Peak",region:"Khumbu",category:"peak",days:18,difficulty:"strenuous",maxAltitude:6476,distanceKm:125,bestMonths:"Apr–May · Oct–Nov",permits:[{name:"NMA climbing permit (spring rate)",npr:33750},{name:"Sagarmatha National Park entry",npr:3e3}],priceMode:"from",priceFromNpr:21e4,summary:"The highest of Nepal's trekking peaks, reached across the roadless Hinku valley. From the summit five 8,000ers stand along the horizon: Everest, Lhotse, Makalu, Kanchenjunga and Cho Oyu.",whatThisIsNot:"This is not a long trek with a photogenic finish: the last days are on crevassed glacier, roped and cramponed, sleeping at a high camp cut into snow.",meetPoint:"Lukla airstrip",teahouses:!1,safetyNote:"Altitude is the hazard: the summit push is long, entirely above 6,000 m, and frostnipped fingers are the classic Mera injury in the pre-dawn cold. Turn-around times are fixed and enforced.",fitnessNote:"Expect back to back six to seven hour walking days, prior time above 5,000 m, and a summit push that can run twelve hours.",operatorId:"op-expedition",badges:["expedition-partner"],palette:"night"},{slug:"lobuche-east",name:"Lobuche East",region:"Khumbu",category:"peak",days:17,difficulty:"strenuous",maxAltitude:6119,distanceKm:115,bestMonths:"Apr–May · Oct–Nov",permits:[{name:"NMA climbing permit (spring rate)",npr:33750},{name:"Sagarmatha National Park entry",npr:3e3}],priceMode:"from",priceFromNpr:195e3,summary:"The technical step above Island Peak, for climbers ready for sustained ground. The summit ridge climbs on fixed lines over exposed snow, with Everest, Nuptse and Ama Dablam ranged across the Khumbu.",whatThisIsNot:"This is not a first summit: jumar work on the fixed lines has to be second nature, because the ridge is steeper and more sustained than the standard trekking peaks.",meetPoint:"Lukla airstrip",teahouses:!1,safetyNote:"The fixed lines cross hard snow above real exposure, and every clip matters when cold hands slow down. AMS compounds every error above 6,000 m.",fitnessNote:"Previous rope-and-crampon experience above 5,500 m expected; summit day runs ten hours or more.",operatorId:"op-expedition",badges:["expedition-partner"],palette:"alpenglow"},{slug:"pisang-peak",name:"Pisang Peak",region:"Annapurna",category:"peak",days:15,difficulty:"strenuous",maxAltitude:6091,distanceKm:90,bestMonths:"Apr–May · Oct–Nov",permits:[{name:"NMA climbing permit (spring rate)",npr:33750},{name:"Annapurna Conservation Area permit",npr:3e3}],priceMode:"from",priceFromNpr:175e3,summary:"A rock and snow pyramid rising straight off the Annapurna Circuit, above the flat roofs and prayer wheels of Upper Pisang's stone village. Annapurna II stands directly across the valley, close enough to read its ice cliffs.",whatThisIsNot:"This is not a side trip you bolt onto the Circuit on a whim: the upper mountain is glaciated, climbed roped in crampons, and booked through an expedition partner in advance.",meetPoint:"Besisahar jeep stand",teahouses:!1,safetyNote:"The summit slope steepens to snow that is climbed roped, with fixed line in icy years, and the Circuit approach gains height fast enough to make AMS a genuine risk.",fitnessNote:"Prior trekking above 4,500 m expected; summit day is eight to ten hours on snow.",operatorId:"op-expedition",badges:["expedition-partner"],palette:"dawn"},{slug:"yala-peak",name:"Yala Peak",region:"Langtang",category:"peak",days:10,difficulty:"demanding",maxAltitude:5732,distanceKm:70,bestMonths:"Apr–May · Oct–Nov",permits:[{name:"Langtang National Park entry",npr:3e3},{name:"TIMS card",npr:2e3}],priceMode:"from",priceFromNpr:125e3,summary:"The gentlest introduction on this list: a walk-up glacier summit above Kyanjin Gompa at the head of the Langtang valley. From the top, Shishapangma stands across the border in Tibet.",whatThisIsNot:"This is the honest exception on the list, a true walk-up, but it still crosses a glacier: you go roped, in crampons, with a climbing partner, not alone in trainers.",meetPoint:"Syabrubesi bus park",teahouses:!1,safetyNote:"Even a gentle glacier hides crevasses under spring snow, and the summit morning is well below freezing; rope up, and acclimatise on the valley walk first.",fitnessNote:"The most approachable climb here: hill fitness and one previous trek near 4,000 m are enough, with a six to eight hour summit day.",operatorId:"op-expedition",badges:["expedition-partner"],palette:"dawn"},{slug:"tent-peak-tharpu-chuli",name:"Tent Peak (Tharpu Chuli)",region:"Annapurna",category:"peak",days:12,difficulty:"strenuous",maxAltitude:5663,distanceKm:80,bestMonths:"Apr–May · Oct–Nov",permits:[{name:"NMA climbing permit (spring rate)",npr:33750},{name:"Annapurna Conservation Area permit",npr:3e3}],priceMode:"from",priceFromNpr:155e3,summary:"Climbed from inside the Annapurna Sanctuary, with base camp on the moraine under Annapurna I's south face. The summit is a roped snow ridge at the centre of the mountain amphitheatre.",whatThisIsNot:"This is not the Sanctuary trek with extra steps: past base camp the glacier is crevassed and the ridge is roped climbing, so it runs with an expedition partner, not a trekking guide.",meetPoint:"Pokhara Lakeside office",teahouses:!1,safetyNote:"The approach gully takes stonefall, so helmets go on early, and the crevassed glacier below the ridge is roped terrain; most slips happen on the tired afternoon descent.",fitnessNote:"Prior high-altitude trekking expected: the Sanctuary approach gains height quickly and summit day is eight to ten hours.",operatorId:"op-expedition",badges:["expedition-partner"],palette:"alpenglow"},{slug:"chulu-east",name:"Chulu East",region:"Annapurna",category:"peak",days:16,difficulty:"strenuous",maxAltitude:6584,distanceKm:100,bestMonths:"Apr–May · Oct–Nov",permits:[{name:"NMA climbing permit (spring rate)",npr:33750},{name:"Annapurna Conservation Area permit",npr:3e3}],priceMode:"from",priceFromNpr:205e3,summary:"From high camp the whole Annapurna wall, Annapurna II through Gangapurna to Tilicho Peak, stands across the Manang valley. The climb itself is a long roped snow ridge, quiet even in high season.",whatThisIsNot:"This is not a high pass with a certificate at the end: it is a glaciated summit higher than Island Peak, on rope and crampons, and colder than most people plan for.",meetPoint:"Besisahar jeep stand",teahouses:!1,safetyNote:"The route sleeps high and summits above 6,500 m, where AMS and cold injuries arrive quietly; fixed turn-around times and a slow rest-step pace are non-negotiable.",fitnessNote:"Prior experience above 5,000 m expected, plus the endurance for a ten to twelve hour summit day.",operatorId:"op-expedition",badges:["expedition-partner"],palette:"night"},{slug:"dhampus-peak",name:"Dhampus Peak",region:"Dhaulagiri",category:"peak",days:13,difficulty:"strenuous",maxAltitude:6012,distanceKm:85,bestMonths:"Apr–May · Oct–Nov",permits:[{name:"NMA climbing permit (autumn rate)",npr:16875},{name:"Annapurna Conservation Area permit",npr:3e3}],priceMode:"from",priceFromNpr:165e3,summary:"Thapa Peak on the climbing permit: a snow dome above French Pass where Dhaulagiri fills the western sky. Below the climb lies Hidden Valley, one of the emptiest high places in Nepal.",whatThisIsNot:"This is not a gentle add-on to a Dhaulagiri trek: the dome is glaciated, the wind above French Pass rarely stops, and you climb roped behind an expedition team.",meetPoint:"Beni bus park, Myagdi",teahouses:!1,safetyNote:"Wind is the signature hazard: the ridge above French Pass funnels it, and summit-morning wind chill can freeze exposed skin in minutes. The dome's crevasses are roped terrain.",fitnessNote:"Prior trekking above 5,000 m expected; the approach days are long and the summit push takes eight to ten hours.",operatorId:"op-expedition",badges:["expedition-partner"],palette:"dawn"},{slug:"great-himalaya-trail",name:"Great Himalaya Trail",region:"Nepal traverse",category:"ght",days:150,difficulty:"strenuous",maxAltitude:6146,distanceKm:1700,bestMonths:"Feb–Oct (east to west with the seasons)",permits:[{name:"Multiple restricted area and conservation permits",npr:25e4}],priceMode:"inquiry",summary:"The full traverse of Nepal, Kanchenjunga in the east to Api in the west, joined along the highest walkable line. Crossings like the Lumba Sumba pass go days between villages.",whatThisIsNot:"This is not a holiday: it is a five month commitment that most people section-hike across several years.",meetPoint:"Kathmandu expedition office, Bouddha",teahouses:!1,safetyNote:"Remoteness is the risk: the high route crosses passes above 6,000 m, days from any road, and evacuation depends on weather windows and insurance that genuinely covers them. Resupply is planned district by district.",fitnessNote:"Months of full walking days back to back: proven multi-week trekking experience, sound joints and a body that recovers overnight are the entry requirements.",operatorId:"op-expedition",badges:["inquiry-only","restricted"],palette:"alpenglow"}],t=[{slug:"pokhara-paragliding",name:"Paragliding over Pokhara",location:"Sarangkot, Pokhara",category:"adventure",duration:"30 min flight",priceFromNpr:9e3,blurb:"Launch off Sarangkot with a certified tandem pilot and ride the thermals above Phewa Lake, the Annapurnas filling the horizon.",story:"Pokhara is one of the best tandem paragliding spots on earth: a high launch at Sarangkot, reliable thermals, and a soft landing on the lakeshore. You run a few steps off the hill with a licensed pilot strapped behind you, and then the ground simply falls away. For the next half hour you share the air with Himalayan griffon vultures, the white wall of the Annapurnas across the valley and Phewa Lake mirroring the sky below. Add an acro option if you want spirals; keep it gentle if you just want the view.",includes:["Certified tandem pilot and full equipment","Hotel pickup to the Sarangkot launch","20 to 30 minutes of airtime","Optional GoPro photos and video"],goodToKnow:"Morning flights are calmest and clearest; afternoons can be bumpy. Weight limits and weather cancellations apply, and monsoon months are largely grounded.",whatThisIsNot:"This is not a guaranteed flight: wind and cloud ground pilots without much notice, and rescheduling is part of the sport.",meetPoint:"Lakeside office, Pokhara (pickup to Sarangkot)",fitness:"any",world:"air",operatorId:"op-air",bestMonths:"Sep–Nov · Feb–Apr",photo:"/photos/activities/pokhara-paragliding.jpg",palette:"lake",lat:28.2442,lng:83.9491},{slug:"chitwan-jungle-safari",name:"Chitwan jungle safari",location:"Chitwan National Park",category:"wildlife",duration:"Full day",priceFromNpr:6500,blurb:"Dawn on the Rapti, then a 4x4 and canoe through Nepal's first national park for one-horned rhino, gharial and, if the jungle is kind, a tiger's pugmark.",story:"Chitwan was Nepal's first national park and is a UNESCO World Heritage site, a pocket of subtropical lowland jungle where greater one-horned rhino graze the grasslands and Bengal tigers leave their prints on the riverbank. A full day mixes a dugout canoe down the Rapti past basking gharial crocodiles, a guided jeep safari deep into the sal forest, and a walk with a naturalist who reads the jungle like a book. Evenings bring a Tharu stick dance around the fire in a village that has lived alongside this jungle for centuries.",includes:["Park entry permit and licensed naturalist guide","Dugout canoe trip on the Rapti","Jeep safari into the core forest","Tharu cultural evening"],goodToKnow:"Wildlife is never guaranteed; rhino sightings are common, tigers rare and a matter of luck. We use park-approved ethical operators only, no elephant-back rides.",whatThisIsNot:"This is not a zoo: animals appear on their own terms, and a day without a tiger is the normal day.",meetPoint:"Sauraha park gate, Chitwan",fitness:"any",world:"wild",operatorId:"op-wild",bestMonths:"Oct–Mar (cool, dry)",photo:"/photos/activities/chitwan-jungle-safari.jpg",palette:"forest",lat:27.5291,lng:84.4542},{slug:"trishuli-rafting",name:"Trishuli river rafting",location:"Trishuli River, Charaudi",category:"water",duration:"Half day",priceFromNpr:4500,blurb:"Class 3 whitewater an easy drive from Kathmandu or Pokhara: big, friendly waves, sandy beaches and a guide who knows every drop by name.",story:"The Trishuli is Nepal's most accessible whitewater, running right alongside the Kathmandu to Pokhara highway, which makes it the perfect first raft or a fun family day. Expect read-and-run Class 2 to 3 rapids with names like Ladies' Delight and Upset, long pools to swim in between, and white-sand beaches for lunch. A river guide briefs you on paddling and safety before you push off, and a safety kayaker shadows the rafts. Go for a half day, or extend to an overnight with a riverside camp.",includes:["Raft, paddle, helmet and life jacket","Trained river guide and safety kayaker","Safety briefing and riverside lunch","Waterproof bag for your kit"],goodToKnow:"Flows are biggest and most exciting right after the monsoon; winter is gentler and colder. You do not need experience, but you should be able to swim.",whatThisIsNot:"This is not a wilderness river: the highway runs alongside most of it, which is exactly what makes it an easy day trip.",meetPoint:"Charaudi put-in, Prithvi Highway",fitness:"any",world:"water",operatorId:"op-rivers",bestMonths:"Sep–Nov · Mar–May",photo:"/photos/activities/trishuli-rafting.jpg",palette:"lake",lat:27.8302,lng:84.8519},{slug:"bhotekoshi-bungee",name:"Bungee jump, Bhote Koshi",location:"The Last Resort, Bhote Koshi",category:"adventure",duration:"Day trip from Kathmandu",priceFromNpr:9500,blurb:"A 160 m plunge from a suspension bridge over a raw Himalayan gorge near the Tibet border, one of the highest natural bungees anywhere.",story:"Three hours from Kathmandu, near the Tibetan border, a steel suspension bridge spans a 160 m gorge with the Bhote Koshi river roaring below. Step off it and you get the longest freefall of your life, a New-Zealand-engineered jump with a perfect safety record. The same site runs a canyon swing, a giant arc that is arguably scarier than the bungee. It is a full day out: the drive up the Araniko Highway through terraced hills is half the experience, and most people make a night of it at the resort.",includes:["160 m bungee jump or canyon swing","Return transport from Kathmandu","Full safety gear and trained jump crew","Lunch at the gorge-side resort"],goodToKnow:"Minimum age and weight limits apply, and there are health restrictions (heart, back, pregnancy). The road can be slow after monsoon landslides.",whatThisIsNot:"This is not a walk-up whim: health restrictions are enforced at the bridge, and the drive is three hours each way.",meetPoint:"Kathmandu pickup point, Araniko Highway",fitness:"any",world:"air",operatorId:"op-air",bestMonths:"Sep–May",photo:"/photos/heroes/home.jpg",palette:"alpenglow",lat:27.8489,lng:85.9525},{slug:"everest-mountain-flight",name:"Everest mountain flight",location:"Departs Kathmandu",category:"scenic",duration:"1 hour",priceFromNpr:26e3,blurb:"A dawn scenic flight that runs the spine of the Himalaya to Everest and back, every seat a window, no trekking required.",story:"Not everyone has two weeks to walk to Everest, and this is the answer: a one-hour mountain flight that lifts off Kathmandu at dawn and flies east along the Himalaya. Every seat is a window seat, guaranteed, and the cabin crew bring you up to the cockpit one by one for the head-on view of Everest, Lhotse and Makalu. It is the whole roof of the world, from Langtang to the Khumbu giants, in the time it takes to drink a coffee. The best hour of light in Nepal, from 25,000 feet.",includes:["Guaranteed window seat","One-hour flight along the high Himalaya","Cockpit visit for the Everest view","A printed peak-identification map"],goodToKnow:"Flights only run in clear weather and are often delayed or cancelled in cloud; build a buffer day. Autumn and winter mornings have the cleanest skies.",whatThisIsNot:"This is not a substitute for the trek: you see the mountain, not the villages and bakeries of the Khumbu, and cloud can hold the flight for days.",meetPoint:"Kathmandu domestic terminal",fitness:"any",world:"air",operatorId:"op-air",bestMonths:"Oct–Mar",photo:"/photos/activities/everest-mountain-flight.jpg",palette:"dawn",lat:27.6966,lng:85.3591},{slug:"pokhara-zipline",name:"Pokhara zipline",location:"Sarangkot to Hemja, Pokhara",category:"adventure",duration:"30 min",priceFromNpr:7500,blurb:"One of the world's steepest and longest ziplines: 1.8 km of cable, 600 m of drop, up to 120 km/h with the lake glittering below.",story:"Billed as one of the world's most extreme ziplines, the Pokhara zip drops 600 vertical metres over 1.8 km of cable strung from Sarangkot down toward Hemja. You clip in, lean back, and hit speeds around 120 km/h with the Annapurnas on one side and Phewa Lake glittering on the other. It lasts barely a couple of minutes but the rush stays with you. Many people pair it with a Sarangkot sunrise and a paraglide for a full morning of air.",includes:["Tandem-capable harness and full gear","Trained operators at launch and landing","Transport between Sarangkot and the base","Optional on-ride photos"],goodToKnow:"Weight limits and weather holds apply. It is over fast; pair it with paragliding or a Sarangkot sunrise to make a morning of it.",whatThisIsNot:"This is not a scenic cruise: it is two minutes of raw speed, over almost before you settle in.",meetPoint:"Sarangkot top station",fitness:"any",world:"air",operatorId:"op-air",bestMonths:"Sep–May",photo:"/photos/heroes/home.jpg",palette:"alpenglow",lat:28.2701,lng:83.9402},{slug:"kathmandu-heritage-tour",name:"Kathmandu Valley heritage tour",location:"Kathmandu, Patan & Bhaktapur",category:"culture",duration:"Full day",priceFromNpr:5500,blurb:"A guided day through three medieval Durbar Squares and the great stupas, seven UNESCO World Heritage monument zones within one valley.",story:"The Kathmandu Valley holds seven UNESCO World Heritage monument zones within a few kilometres of each other. A full guided day links the medieval royal squares of Kathmandu, Patan and Bhaktapur, with their carved-wood palaces and pagoda temples, to the great stupas of Swayambhunath and Boudhanath. A local historian guide turns the carvings and courtyards into stories of the Malla kings, living goddesses and the artisans who still work the same crafts today. It is the cultural heart of the country in a single, walkable day.",includes:["Private historian guide for the day","Three Durbar Squares plus the great stupas","Site entry fees included","Air-conditioned transport between sites"],goodToKnow:"It is a lot of walking on uneven stone; comfortable shoes matter. Dress modestly for the temples (shoulders and knees covered).",whatThisIsNot:"This is not a quiet museum day: the squares are living markets, loud and crowded, and earthquake scaffolding still wraps some temples.",meetPoint:"Your Kathmandu hotel lobby",fitness:"any",world:"sacred",operatorId:"op-heritage",bestMonths:"Year-round",photo:"/photos/activities/kathmandu-heritage-tour.jpg",palette:"day",lat:27.7045,lng:85.307},{slug:"phewa-boating",name:"Phewa Lake boating",location:"Lakeside, Pokhara",category:"water",duration:"1 to 2 hours",priceFromNpr:1200,blurb:"A painted wooden doonga across still water to the island shrine of Tal Barahi, the Annapurnas mirrored on the surface at golden hour.",story:"The gentlest experience in Pokhara, and one of the loveliest. A brightly painted wooden doonga carries you out onto Phewa Lake, either rowed by a boatman or paddled yourself, to the small two-tiered pagoda of Tal Barahi sitting on its own island. At golden hour the Annapurnas and the fishtail peak of Machapuchare lay themselves out on the still water, once in the sky and once in the reflection. Time it for sunset, light a lamp at the shrine, and drift back as Lakeside switches on its lights.",includes:["Wooden boat hire (rowed or self-paddle)","Visit to the Tal Barahi island shrine","Life jackets provided","Best timed for sunset"],goodToKnow:"Self-rowing is cheap and easy on the calm lake; a boatman is a small extra. The shrine gets busy on Saturdays and festival days.",whatThisIsNot:"This is not an adrenaline ride: it is slow by design, and the mountain reflection needs still air and a clear sky to show up.",meetPoint:"Barahi Ghat, Lakeside",fitness:"any",world:"calm",operatorId:"op-annapurna",bestMonths:"Year-round (clearest Oct–Apr)",photo:"/photos/activities/phewa-boating.jpg",palette:"lake",lat:28.2096,lng:83.9456},{slug:"everest-heli-tour",name:"Everest Base Camp heli tour",location:"Departs Kathmandu",category:"scenic",duration:"About 4 hours",priceFromNpr:165e3,blurb:"Helicopter to the Khumbu with a landing at Kala Patthar for the close-up of Everest, and breakfast at Hotel Everest View on the way back.",story:"The fastest way to stand among the Everest giants. A helicopter lifts from Kathmandu, refuels at Lukla, and flies you up the Khumbu valley to a landing near Kala Patthar or Everest Base Camp at well over 5,000 m, the close-up most people walk twelve days for. The air up there is razor-thin, so the landing stays deliberately brief, and then you drop to Hotel Everest View for breakfast with Ama Dablam framed in the window. Shared charters keep the cost down; a private flight gives you the whole cabin and the timing.",includes:["Helicopter from Kathmandu, return","Landing near Kala Patthar / Base Camp","Breakfast at Hotel Everest View","Oxygen on board and a flight crew briefing"],goodToKnow:"The high landing is short to manage altitude, and weather can reroute or cancel the day. Shared seats are far cheaper than a private charter.",whatThisIsNot:"This is not a long visit: the high landing lasts minutes to keep the altitude safe, and weather can reroute the whole morning.",meetPoint:"Kathmandu domestic terminal",fitness:"any",world:"air",operatorId:"op-air",bestMonths:"Oct–Nov · Mar–Apr",photo:"/photos/activities/everest-heli-tour.jpg",palette:"dawn",lat:27.9881,lng:86.8292},{slug:"bandipur-paragliding",name:"Paragliding over Bandipur",location:"Bandipur, Tanahun",category:"adventure",world:"air",duration:"20 min flight",priceFromNpr:8e3,blurb:"Run off the ridge above Bandipur's traffic-free bazaar and glide out over the Marsyangdi valley, a quieter launch than Pokhara with the same white wall to the north.",story:"Bandipur sits on a saddle above the Marsyangdi, and the launch is a short walk up from the old Newari bazaar. A tandem pilot clips in behind you, you take a few running steps, and the hillside gives way to terraced fields far below. Traffic here is a handful of wings, not a morning queue, and on a clear day the ridgeline frames Himalchuli and Manaslu. You land down in the valley and jeep back up in time for coffee on the flagstones.",includes:["Certified tandem pilot and full kit","Briefing at the ridge launch above the bazaar","Valley landing and jeep back up to town","Optional in-flight photos"],goodToKnow:"Flights go in the calm morning slot; cloud sitting on the ridge holds or cancels them. Book the evening before from your guesthouse in the bazaar.",whatThisIsNot:"This is not big-mountain soaring: the ridge serves a gentle glide down to the valley floor, not an hour of chasing thermals.",meetPoint:"Bandipur bazaar",fitness:"active",operatorId:"op-air",bestMonths:"Oct–Apr",palette:"day",lat:27.94,lng:84.41},{slug:"pokhara-ultralight-flight",name:"Ultralight flight, Pokhara",location:"Pokhara airport",category:"scenic",world:"air",duration:"15 to 60 min flight",priceFromNpr:18e3,blurb:"An open-cockpit aircraft barely bigger than a motorbike lifts off the grass at Pokhara and points at the Annapurnas, wind on your face and Machapuchare dead ahead.",story:"The ultralight is flying at its most honest: a two-seat open cockpit, pilot in front, you behind, and the Pokhara valley opening beneath your boots. Short slots circle Phewa Lake and the World Peace Pagoda; longer ones climb toward the Annapurna wall until Machapuchare's fishtail summit sits level with your visor. Flights leave in the smooth morning air from the ultralight apron at Pokhara airport, and every minute of it is camera-out flying.",includes:["Pilot and open-cockpit two-seater","Flight suit, goggles and radio headset","Choice of lake circuit or Annapurna approach","Hotel pickup from Lakeside"],goodToKnow:"Mornings only, when the air is smooth, and the schedule collapses in cloud or wind. The base fare buys the shortest loop; the mountain approaches cost more, and a passenger weight limit applies.",whatThisIsNot:"This is not a sealed cabin: you feel every degree of the altitude chill, and a winter flight needs every layer you brought to Nepal.",meetPoint:"Pokhara airport, ultralight hangar",fitness:"any",operatorId:"op-air",bestMonths:"Sep–Jun",palette:"dawn",lat:28.2,lng:83.98},{slug:"annapurna-heli-tour",name:"Annapurna Base Camp heli tour",location:"Departs Pokhara",category:"scenic",world:"air",duration:"About 3 hours",priceFromNpr:95e3,blurb:"Lift out of Pokhara, thread the Modi Khola gorge and land inside the Annapurna Sanctuary, the ring of ice walls trekkers walk five days to enter.",story:"The Sanctuary is a natural amphitheatre: one gorge in, then a bowl of glacier with Annapurna I's south face on one side and Machapuchare's spire on the other. The helicopter follows the Modi Khola past Chhomrong's terraces and sets down at base camp, 4,130 m, for a short landing among the prayer flags and moraine. Tea at the lodge, photographs, and the same wild corridor home. Shared seats fly most clear mornings in season.",includes:["Helicopter from Pokhara, return","Landing at Annapurna Base Camp","Tea stop and time for photographs","Pre-flight briefing and oxygen on board"],goodToKnow:"The ground stop is kept short because you land at altitude with no acclimatisation. Shared-seat pricing needs the flight to fill; a private charter costs several times the seat rate.",whatThisIsNot:"This is not a guaranteed departure: Sanctuary weather closes the gorge without apology, and mornings shift or cancel at an hour's notice.",meetPoint:"Pokhara airport, heli charter gate",fitness:"any",operatorId:"op-air",bestMonths:"Oct–Nov · Mar–Apr",palette:"alpenglow",lat:28.2,lng:83.98},{slug:"langtang-heli-tour",name:"Langtang heli day",location:"Departs Kathmandu",category:"scenic",world:"air",duration:"About 2.5 hours",priceFromNpr:78e3,blurb:"The closest glacier country to Kathmandu: fly up the Langtang gorge and land on the yak pasture at Kyanjin Gompa, under the ice wall of Langtang Lirung.",story:"The helicopter turns up the Langtang gorge past the scar of the 2015 landslide and sets down on the pasture at Kyanjin Gompa, where Langtang Lirung's amphitheatre fills the whole northern sky. There is time on the ground for the monastery and a slab of yak cheese from the dairy that has worked here since the 1950s, then the gorge unwinds beneath you on the run home. Glacier country before lunch, from a Kathmandu breakfast.",includes:["Helicopter from Kathmandu, return","Landing at Kyanjin Gompa","Ground time for the monastery and cheese dairy","Pre-flight briefing and oxygen on board"],goodToKnow:"Kyanjin sits near 3,900 m, so the stop is short and gentle; tell the crew if a headache starts. Shared seats fly on set mornings, private charters on yours.",whatThisIsNot:"This is not a view guarantee: cloud fills the Langtang gorge fast, and flights reroute or turn back when it does.",meetPoint:"Kathmandu domestic terminal",fitness:"any",operatorId:"op-air",bestMonths:"Oct–Dec · Mar–Apr",palette:"alpenglow",lat:27.696,lng:85.359},{slug:"rara-heli-tour",name:"Rara Lake heli day",location:"Rara Lake, Mugu",category:"scenic",world:"air",duration:"About 4 hours",priceFromNpr:185e3,blurb:"Nepal's biggest lake lies in the far northwest, normally two flights and a walk away. A helicopter puts you on its pine-ringed shore for a morning and home for dinner.",story:"Rara is the lake Nepalis tell each other about: a sheet of blue at 2,990 m inside the country's smallest national park, ringed by pine and juniper and a very long way from anywhere. Getting there normally means flights to Nepalgunj and Talcha and a walk; the helicopter does it in a morning, refuelling at Nepalgunj before climbing into Mugu's ridgelines. You get an hour or so on the shore, the water changing colour as the light moves, before the long run home.",includes:["Helicopter from Kathmandu with Nepalgunj fuel stop","Landing on the Rara lakeshore","About an hour of ground time at the lake","Rara National Park entry arranged"],goodToKnow:"This is the long-range premium of the heli list, and it hangs on two weather windows at once: Kathmandu's and Mugu's. Winter snow can close the lakeshore landing for weeks.",whatThisIsNot:"This is not a picnic day with slack in it: ground time is rationed by fuel and wind, and the afternoon build-up decides when you leave, not you.",meetPoint:"Kathmandu domestic terminal",fitness:"any",operatorId:"op-air",bestMonths:"Oct–Nov · Apr–May",palette:"lake",lat:29.52,lng:82.09},{slug:"pokhara-hot-air-balloon",name:"Hot air balloon, Pokhara",location:"Pame, Pokhara",category:"scenic",world:"air",duration:"1 hour flight",priceFromNpr:19500,blurb:"Stand in a wicker basket at 3,000 m over the Pokhara valley while the burner goes quiet and Machapuchare holds still at eye level.",story:"Balloon mornings start in the dark at the Pame launch field, the envelope inflating like a building waking up. Lift-off comes at first light, and the drift is slow enough to watch woodsmoke rise from Lakeside below. At height the pilot cuts the burner and lets the valley go silent: Phewa Lake glints, the Annapurnas line the north, and Machapuchare sits level with the basket rim. You land wherever the wind offers a field, which is half the charm, and a jeep tracks you home.",includes:["Certified balloon pilot and ground crew","Dawn transfer to the Pame launch field","Light breakfast after the landing","Pickup from the landing field back to Lakeside"],goodToKnow:"Winter mornings are the clearest and the coldest, so dress for standing still in moving air. The basket is an open wicker box: fine for most people, unkind to bad knees at the landing bump.",whatThisIsNot:"This is not a precision itinerary: the wind picks the track and the landing field, and marginal mornings scrub before sunrise.",meetPoint:"Lakeside office, Pokhara (dawn transfer to Pame)",fitness:"any",operatorId:"op-air",bestMonths:"Oct–Apr",palette:"dawn",lat:28.23,lng:83.9},{slug:"everest-skydive",name:"Everest skydive",location:"Syangboche, Khumbu",category:"adventure",world:"air",duration:"Multi-day package",priceFromNpr:495e3,blurb:"Exit the aircraft at around 7,000 m with Everest filling the horizon, and land on the grass shelf at Syangboche, the world's highest drop zone. Nothing else we list asks for more nerve, or more money.",story:"Syangboche's airstrip above Namche Bazaar is the highest drop zone on earth, and for a short window each autumn it hosts tandem skydives. You acclimatise in the Khumbu first, because the exit happens at altitudes where climbers breathe bottled oxygen, and you will too. Then the aircraft climbs, the door opens on Everest, Lhotse and Ama Dablam, and you fall with a tandem master strapped to your back toward a landing at 3,780 m. Nothing in Nepal compares to the commitment.",includes:["Tandem master and high-altitude jump kit","Bottled oxygen for the exit altitude","Positioning flights and acclimatisation days in the Khumbu","Drop-zone ground crew at Syangboche"],goodToKnow:"Runs only in a short November window, and the fee is a package built around it: acclimatisation days, positioning flights and the jump itself. Strict weight, health and paperwork checks apply.",whatThisIsNot:"This is not an impulse jump: November is the only month it runs, places are few, and the altitude rules can still ground you after you have flown halfway around the world.",meetPoint:"Kathmandu domestic terminal",fitness:"active",operatorId:"op-air",bestMonths:"Nov",palette:"day",lat:27.8119,lng:86.7124},{slug:"kushma-bungee",name:"Kushma bungee",location:"Kushma, Parbat",category:"adventure",world:"air",duration:"Half day from Pokhara",priceFromNpr:12e3,blurb:"Step off a suspension bridge 228 m above the Kali Gandaki, one of the highest natural bungee jumps in the world, with the gorge wind coming up to meet you.",story:"Kushma has turned its gorge into a national attraction. A purpose-built suspension bridge hangs between Kushma and Balewa, high over the grey glacial water of the Kali Gandaki, the river that carves the deepest gorge system on earth further north. The crew weighs you, chalks the number on your hand, rigs the cord and counts you down. The freefall lasts long enough to hear yourself think again before the recoil, and spectators can watch from the bridge deck, which does nothing for your nerves.",includes:["Bridge jump with full rigging","Trained jump crew and weigh-in briefing","Bridge access for companions to watch","Jump certificate"],goodToKnow:"Weight limits and health restrictions are enforced at the weigh-in, not negotiated at the platform. Kushma is about two hours by road from Pokhara, and the gorge wind picks up by afternoon.",whatThisIsNot:"This is not a place to talk yourself into it slowly: jumps run to a schedule, and the crew will cycle past you if you freeze at the edge.",meetPoint:"Kushma bridge platform, Parbat",fitness:"active",operatorId:"op-air",bestMonths:"Sep–Jun",palette:"day",lat:28.21,lng:83.68},{slug:"pokhara-tower-bungee",name:"Pokhara tower bungee",location:"Hemja, Pokhara",category:"adventure",world:"air",duration:"2 hours",priceFromNpr:7500,blurb:"An 80 m purpose-built bungee tower on Pokhara's edge with a pond below the deck: ask the crew for a water touch and they will tune the cord to a fingertip.",story:"Not everyone has a day to give a gorge, and the Hemja tower is the answer: a steel bungee tower on the northern edge of Pokhara, minutes of paperwork and you are climbing to the deck. The pond underneath lets the crew set your cord for a fingertip water touch if you ask, dry hair if you do not, and Machapuchare watches from up the valley. It is the quick way to learn whether the Kushma bridge should be your next stop.",includes:["Tower jump with full rigging","Trained crew and weigh-in","Optional water-touch cord setting","Viewing area for companions"],goodToKnow:"Sessions run at fixed times through the day; the weigh-in decides your cord and pockets must be empty before the deck. The Sarangkot zipline finishes nearby if you want a full morning of it.",whatThisIsNot:"This is not the gorge: the tower trades wild scenery for convenience, and the thrill is the drop itself, not the setting.",meetPoint:"Hemja tower gate, Pokhara",fitness:"active",operatorId:"op-air",bestMonths:"Year-round",palette:"lake",lat:28.28,lng:83.93},{slug:"dhulikhel-zipline",name:"Dhulikhel zipline",location:"Dhulikhel, Kavre",category:"adventure",world:"air",duration:"Half day from Kathmandu",priceFromNpr:4500,blurb:"A kilometre of cable strung above Dhulikhel's terraced fields, the old Newari town behind you and, on a clear morning, the Himalaya from Ganesh Himal to Gaurishankar ahead.",story:"Dhulikhel is where Kathmandu goes for mountain air, an old Newari trading town on the valley rim about an hour from the city. The zipline runs off the ridge above town and sends you out over terraces of mustard and potato, harnessed flat in the flying position, the line singing. The ride itself is over quickly, so make the trip earn its keep: walk the carved windows of the old bazaar afterwards, or climb the thousand steps to the Kali temple for the full mountain line-up.",includes:["Zipline run with harness, helmet and briefing","Trained crew at launch and landing","Shuttle back to Dhulikhel old town"],goodToKnow:"Easy to pair with Namobuddha or Panauti on the same day, and winter mornings give the sharpest mountain views before the haze builds.",whatThisIsNot:"This is not a big-ticket adrenaline day: the ride is short and friendly, and the town around it is at least half the reason to come.",meetPoint:"Dhulikhel zipline base",fitness:"any",operatorId:"op-air",bestMonths:"Sep–May",palette:"day",lat:27.62,lng:85.55},{slug:"pokhara-paramotoring",name:"Paramotoring, Pokhara",location:"Pokhara lakeshore",category:"scenic",world:"air",duration:"20 to 30 min flight",priceFromNpr:14e3,blurb:"A paraglider with an engine on the pilot's back: take off from a flat lakeshore field at sunrise and cruise the length of Phewa at whatever height the view deserves.",story:"Paragliding waits for midday thermals; paramotoring does not. The two-stroke motor on your pilot's back lets you launch from a flat field by the lake in the still air just after sunrise, a short tandem run and then up. You cruise the shoreline while Lakeside wakes, circle Tal Barahi's island temple, climb until the Annapurna wall clears the ridgeline, and land back on the same grass you ran off. It suits people who want the air without the leap.",includes:["Certified tandem paramotor pilot","Helmet, radio headset and flight kit","Sunrise slot with launch-field transfer","Optional in-flight photos"],goodToKnow:"The launch is a short run beside the pilot until the wing lifts, so you need working knees. The engine is loud even through the headset, and the sunrise slots are the calmest.",whatThisIsNot:"This is not silent flight: the motor drones behind you the whole way, which is the price of taking off without a hill.",meetPoint:"Khapaudi launch field, Pokhara lakeshore",fitness:"active",operatorId:"op-air",bestMonths:"Oct–Apr",palette:"dawn",lat:28.23,lng:83.93},{slug:"bhotekoshi-rafting",name:"Bhote Koshi rafting",location:"Bhote Koshi, Sindhupalchok",category:"water",world:"water",duration:"Half day",priceFromNpr:5500,blurb:"The steepest short run in Nepal: the river drops through a narrow gorge near the Tibet border and barely pauses between rapids. You are paddling hard from the first eddy to the last.",story:"The Bhote Koshi packs more gradient into a morning than any other commercial run in the country. Rapids with names like Frog in a Blender and Gerbil in the Plumbing arrive back to back, continuous Class 4 water in a gorge tight enough that the guide's commands replace conversation. Trips run the section above Lamosangu with a safety kayaker shadowing every raft, and the take-out beach has hot tea waiting. It is short, intense and over by lunch.",includes:["Raft, helmet, wetsuit and life jacket","Safety kayaker alongside every raft","Full paddle briefing and bank scouts at the big drops","Hot drinks at the take-out beach"],goodToKnow:"You must be a confident swimmer and quick on commands. Flows change the grading: right after the monsoon the run stiffens a full class, and winter water is cold enough to want the wetsuit zipped.",whatThisIsNot:"This is not a first river: the rapids are continuous, swims happen, and guides will move a nervous paddler to the gear raft without apology.",meetPoint:"Baseri put-in, Araniko Highway",fitness:"active",operatorId:"op-rivers",bestMonths:"Sep–Nov · Mar–May",palette:"forest",lat:27.79,lng:85.9},{slug:"kali-gandaki-rafting",name:"Kali Gandaki rafting",location:"Kali Gandaki, west of Pokhara",category:"water",world:"water",duration:"3 days",priceFromNpr:16500,blurb:"A holy river through the deepest gorge country below the Annapurnas, far enough from any road that the nights belong to the water. Class 3 to 4 rapids by day, driftwood fires on sand by night.",story:"The Kali Gandaki cuts between the Annapurna and Dhaulagiri massifs before it reaches this run, and it arrives carrying glacier silt and prayer. Rapids named Small Brother and Big Brother punctuate long green corridors where the only landmarks are the shrine at Setibeni and a scatter of suspension bridges. Camps go up on white-sand beaches, the kitchen crew bakes over driftwood coals, and the trip takes out at Mirmi above the dam.",includes:["Rafts, camping kit and dry bags","River guides, safety kayaker and full camp crew","All riverside meals from put-in to take-out","Transfers from Pokhara to the river and back"],goodToKnow:"The gorge holds sacred sites and cremation ghats, and guides will ask for quiet at certain bends. Beaches shrink at high water in early autumn; nights on the sand turn cold from December.",whatThisIsNot:"This is not a spa float: two nights in tents, drop-toilets dug above the tideline, and no phone signal for most of the gorge.",meetPoint:"Lakeside departure point, Pokhara",fitness:"active",operatorId:"op-rivers",bestMonths:"Sep–Nov · Mar–May",palette:"forest",lat:28,lng:83.6},{slug:"seti-river-rafting",name:"Seti River float",location:"Seti River, Damauli",category:"water",world:"water",duration:"Full day",priceFromNpr:4200,blurb:"Warm, jade-green water and rapids that splash rather than punch: the Seti is the river for families, first-timers and anyone who wants to watch birds between waves. Bring the kids and the binoculars.",story:"The Seti is the warmest river commonly rafted in Nepal, spring-fed and gentle, and its Class 2 water reads like a picture book: a riffle, a pool, a heron lifting off a midstream boulder. From the put-in at Damauli the river slips through low jungle gorges where egrets and kingfishers work the shallows, with long calm stretches for swimming beside the raft. Take-out comes near Gaighat, upstream of the sacred confluence at Devghat.",includes:["Raft, paddle, helmet and life jacket","River guide and safety kayaker","Riverside picnic lunch","Child-size life jackets and helmets on request"],goodToKnow:"This is the river to choose if someone in the group is nervous: warm water, easy rapids and plenty of time floating. Levels drop through spring, so late-season trips run gentler still.",whatThisIsNot:"This is not white-knuckle rafting: thrill-seekers will find the rapids polite, and that is exactly the point.",meetPoint:"Damauli put-in, Prithvi Highway",fitness:"any",operatorId:"op-rivers",bestMonths:"Sep–May",palette:"lake",lat:28.1,lng:84.05},{slug:"sunkoshi-expedition",name:"Sun Koshi expedition",location:"Sun Koshi, Dolalghat to Chatra",category:"water",world:"water",duration:"9 days",priceFromNpr:68e3,blurb:"One of the world's classic multi-day river journeys: 270 km of warm water from the mid-hills to the Gangetic plain, and every camp a private sand beach. Day by day the hills lower and the river widens.",story:"The Sun Koshi, the river of gold, runs the length of eastern Nepal on its way to the Ganges, and descending it is a journey rather than a sport. Early days build through friendly water, then the gorge tightens for the Harkapur rapids and the long Class 4 read at Meat Grinder. In between are white beaches, driftwood fires and villages that still wave at rafts. The take-out at Chatra arrives where the last hill stops and the plains simply begin.",includes:["Expedition rafts, gear raft and dry bags","River guides, safety kayakers and camp crew","All meals and beach camps for the full run","Transfers from Kathmandu to the put-in and back from Chatra"],goodToKnow:"Warm water and big volume make this the friendliest of the long expeditions, but afternoon headwinds on the lower river mean early starts. Bring double sun protection: the water reflects everything.",whatThisIsNot:"This is not a trip you can step off: past Dolalghat there is no road for days, phone signal is a rumour, and the toilet is a spade-dug pit behind a tarp.",meetPoint:"Thamel departure point, Kathmandu",fitness:"active",operatorId:"op-rivers",bestMonths:"Sep–Nov · Mar–May",palette:"lake",lat:27.64,lng:85.71},{slug:"karnali-expedition",name:"Karnali expedition",location:"Karnali River, far west",category:"water",world:"water",duration:"10 days",priceFromNpr:85e3,blurb:"Nepal's biggest river and its wildest expedition: huge Class 4 to 5 water in the far west, days from the nearest road. When river people talk about the trip of their lives, it is usually this one.",story:"The Karnali drains off Tibet near Mount Kailash and crosses the remotest quarter of Nepal, and its expedition section is the country's benchmark big water. Rapids like God's House and Flip and Strip guard the entrance to the Jungle Corridor, a long canyon where langurs watch from the sal forest and the beaches print with deer tracks overnight. The river finally slows at Chisapani on the edge of Bardiya National Park, where Gangetic dolphins sometimes roll beside the rafts.",includes:["Expedition rafts, safety kayakers and swiftwater-trained guides","Full camp crew and all riverside meals","Wetsuits, dry bags and camp kit","Overland transfers to the Sauli put-in and out from Chisapani"],goodToKnow:"Getting there is part of the undertaking: a long drive beyond Surkhet, then a walk down to the put-in. Flows swing hard with the season, and at high water several rapids are scouted or portaged.",whatThisIsNot:"This is not a beginner's expedition: Class 5 water in genuine wilderness means long swims have consequences, and evacuation from the Jungle Corridor is measured in days, not hours.",meetPoint:"Thamel departure point, Kathmandu",fitness:"fit",operatorId:"op-rivers",bestMonths:"Sep–Nov · Mar–May",palette:"forest",lat:28.64,lng:81.28},{slug:"tamur-expedition",name:"Tamur expedition",location:"Tamur River, far east",category:"water",world:"water",duration:"8 days",priceFromNpr:72e3,blurb:"The far-east river you earn on foot: a ridge trek with Kanchenjunga on the skyline, then steep, technical Class 4 water down to the plains. Effort in, whitewater out.",story:"No road reaches the upper Tamur, which is the whole point. The trip walks in from Basantapur over the rhododendron crest of the Milke Danda, drops to the put-in at Dobhan where the Kabeli joins, and then the river takes over: cold, quick and busy, with rapids stacked through the first gorges. Kanchenjunga's meltwater keeps the volume honest all the way to the take-out at Chatra, where the Tamur joins the great braid of the Sapta Koshi.",includes:["Porters and camp crew for the trek-in","Expedition rafts, safety kayakers and river guides","All meals, tents and beach camps","Transfers from Kathmandu to Basantapur and back from Chatra"],goodToKnow:"Roughly half the itinerary is on foot before you touch water, so trekking fitness matters as much as paddling. The window is narrow: post-monsoon carries the best flows, and spring runs lower and rockier.",whatThisIsNot:"This is not an easy logistics trip: long drives bookend it, camps are basic on both trail and beach, and there is no quick way out of the valley once you commit.",meetPoint:"Thamel departure point, Kathmandu",fitness:"active",operatorId:"op-rivers",bestMonths:"Sep–Nov · Mar–May",palette:"forest",lat:26.93,lng:87.33},{slug:"marshyangdi-rafting",name:"Marshyangdi rafting",location:"Marshyangdi River, Lamjung",category:"water",world:"water",duration:"2 days",priceFromNpr:14500,blurb:"Steep, technical and relentless under the Annapurnas: the Marshyangdi is the river people graduate to, not start on. Come with a river or two behind you and it repays every stroke.",story:"Marshyangdi translates as raging river, and the name is a fair briefing. From the put-in near Ngadi above Besisahar the water pours over boulder gardens in near-continuous Class 4 to 5, with Annapurna II and Himalchuli standing over the valley when you get half a second to look up. Guides scout the hardest drops from the bank, the overnight camp goes up on a terrace above the water, and the second morning starts cold and fast.",includes:["Rafts, wetsuits, helmets and dry bags","Guides and safety kayakers who know every drop","Overnight riverside camp and all meals","Bank scouts and a full briefing before the hard sections"],goodToKnow:"Operators will ask about your river history and mean it: previous Class 4 experience is the entry ticket. Hydropower work has shortened the classic run, so itineraries follow the water that still flows free.",whatThisIsNot:"This is not a step up from the Trishuli so much as a leap: swimmers get worked in continuous water, and guides will stand a raft down if the crew is not paddling as one.",meetPoint:"Besisahar bazar, Lamjung",fitness:"fit",operatorId:"op-rivers",bestMonths:"Sep–Nov · Mar–May",palette:"lake",lat:28.23,lng:84.37},{slug:"pokhara-kayak-clinic",name:"Kayak clinic, Pokhara",location:"Phewa Lake and lower Seti, Pokhara",category:"water",world:"water",duration:"4 days",priceFromNpr:24e3,blurb:"Learn the sport, not just the ride: flat-water skills and your first roll on Phewa Lake, then real moving water on the lower Seti. By the last day you are reading the river yourself.",story:"Pokhara is Nepal's kayak school, and this clinic is the standard syllabus done properly. Mornings start on Phewa's flat water in front of the Tal Barahi shrine: wet exits, T-rescues, then the roll, drilled until it stops being frightening. Once the basics hold, the clinic moves to the warm, forgiving Class 2 of the lower Seti near Damauli, where you learn eddies, ferries and the etiquette of moving water with an instructor within reach the whole time.",includes:["Kayak, paddle, spraydeck, helmet and buoyancy aid","Qualified instructor with a small group","Lake sessions plus river days on the lower Seti","Transport between Lakeside and the river"],goodToKnow:"Expect to swim a lot in the first days; that is the syllabus working. Winter mornings on the lake stay cold until the sun clears the ridge, so session times shift with the season.",whatThisIsNot:"This is not a guaranteed roll: some paddlers leave with it bombproof, others with homework, and honest instructors say so on day one.",meetPoint:"Lakeside kayak beach, Pokhara",fitness:"active",operatorId:"op-rivers",bestMonths:"Oct–Apr",palette:"lake",lat:28.21,lng:83.94},{slug:"jalbire-canyoning",name:"Jalbire canyoning",location:"Jalbire, Sindhupalchok",category:"water",world:"water",duration:"Full day",priceFromNpr:6500,blurb:"Clip in at the lip of a waterfall and walk backwards into the spray: a canyon day of abseils, slides and plunge pools within a morning's drive of Kathmandu. The biggest drop is 45 metres of polished rock and falling water.",story:"Jalbire sits just off the Araniko Highway on the road toward the Bhote Koshi, where a side stream has cut a staircase of waterfalls into the hillside above the Balephi Khola. After a rope briefing you descend the canyon in wetsuit and harness: short warm-up abseils first, then longer pitches under full waterfalls, with natural rock slides and jumps between them. Guides rig and check every rope, and the canyon lets you out beside the village in time for a late dal bhat.",includes:["Wetsuit, harness and helmet","Qualified canyoning guides and all rope work","Return transport from Kathmandu","Dal bhat lunch in Jalbire village"],goodToKnow:"You should be comfortable in cold, moving water and fine with heights on a rope. After heavy rain the canyon closes: flow decides the day, not the calendar.",whatThisIsNot:"This is not abseiling in a dry gym: the water pushes at you on every pitch, and the walk between drops is slippery, shin-deep scrambling.",meetPoint:"Thamel departure point, Kathmandu",fitness:"active",operatorId:"op-rivers",bestMonths:"Sep–Nov · Mar–May",palette:"forest",lat:27.79,lng:85.75},{slug:"sundarijal-canyoning",name:"Sundarijal canyoning",location:"Sundarijal, Shivapuri",category:"water",world:"water",duration:"Half day",priceFromNpr:5e3,blurb:"The closest waterfall abseils to Kathmandu: a morning in the Shivapuri watershed canyon where the Bagmati begins, minutes past the last bus stop. City breakfast, canyon by ten.",story:"Sundarijal is where Kathmandu's drinking water comes down off Shivapuri, and the same steep stream makes a compact canyoning run inside the national park gate. You climb the stone steps past the old water pipeline, then descend the gorge on ropes: a chain of abseils down mossy rock and through waterfall spray, with pools to swim between pitches. It is the introduction canyon, close enough to the city that you can be back in Thamel for lunch with your ears still full of water.",includes:["Wetsuit, harness and helmet","Qualified guides and all rope rigging","Shivapuri Nagarjun park entry","Hot tea at the tea shop below the gorge"],goodToKnow:"The water comes straight off Shivapuri and is cold even in October; wetsuits are not optional. Weekends bring picnic crowds to the lower falls, so early starts get the canyon quiet.",whatThisIsNot:"This is not the big-drop canyon: the pitches here are modest, and if you want the long freefall abseils you graduate to Jalbire or the Bhote Koshi.",meetPoint:"Sundarijal entrance gate, Shivapuri Nagarjun National Park",fitness:"active",operatorId:"op-rivers",bestMonths:"Sep–Nov · Mar–May",palette:"forest",lat:27.77,lng:85.42},{slug:"bhotekoshi-canyoning",name:"Bhote Koshi canyoning",location:"Bhote Koshi valley, Sindhupalchok",category:"water",world:"water",duration:"Full day",priceFromNpr:7e3,blurb:"The biggest canyoning drops in the valley that taught Nepal adrenaline: long abseils down waterfalls that hammer the back of your helmet. Most people pair it with the bungee and stay the night.",story:"Canyoning came to Nepal in this valley, in the tributary gorges that drop toward the Bhote Koshi near the Tibet border. The route works down a series of falls with the valley's signature scale: sustained abseils on thundering water, canyon walls close enough to touch on both sides, and pools deep enough for proper jumps. Gorge-side resorts run it back to back with the 160 m bungee, which is why the overnight package exists: one day for the ropes, one for the ledge.",includes:["Wetsuit, harness, helmet and canyon rigging","Guides trained on the valley's long pitches","Lunch at the gorge-side resort","Optional bungee-and-canyon overnight add-on"],goodToKnow:"This is the step up from Jalbire and Sundarijal: longer pitches, colder water, more commitment. Landslides on the Araniko Highway can stretch the drive, so treat timings as generous.",whatThisIsNot:"This is not a first canyon: once you are over the lip of the big abseil there is no walking back up, and the cold works on you pitch after pitch.",meetPoint:"Bhote Koshi resort base, Araniko Highway",fitness:"active",operatorId:"op-rivers",bestMonths:"Sep–Nov · Mar–May",palette:"forest",lat:27.79,lng:85.9},{slug:"phewa-sup",name:"Stand-up paddleboarding, Phewa",location:"Phewa Lake, Pokhara",category:"water",world:"water",duration:"2 hours",priceFromNpr:2200,blurb:"Dawn on Phewa is glass, and a paddleboard is the quietest thing on it: just you, the dip of the paddle, and Machapuchare upside down in the lake. The town is still asleep when you launch.",story:"The session starts before the doongas wake: boards go on the water at first light from the north end of Lakeside, when the lake is at its stillest and the Annapurnas catch the first colour. Beginners find their feet inside ten minutes on flat water; steadier paddlers strike out for the middle of the lake or a slow lap past the Tal Barahi island shrine. By the time the breeze arrives with mid-morning, you are back on shore ordering breakfast.",includes:["Board, paddle, leash and buoyancy aid","Launch briefing and stance basics","Dawn slot when the water is stillest","Dry bag for phone and camera"],goodToKnow:"You will probably fall in at least once, and the lake is cold from December to February; bring a change of clothes. Wind builds most days by late morning, which is why the dawn slot exists.",whatThisIsNot:"This is not an all-day hire: the glass window closes when the breeze arrives, and afternoon water is choppier and busier with boats.",meetPoint:"Khahare beach, north Lakeside",fitness:"any",operatorId:"op-rivers",bestMonths:"Oct–Apr",palette:"lake",lat:28.21,lng:83.94},{slug:"begnas-boating",name:"Begnas Lake boating",location:"Begnas Lake, east of Pokhara",category:"water",world:"water",duration:"2 hours",priceFromNpr:1400,blurb:"The quiet lake east of Pokhara: a wooden boat, terraced hills to the waterline, and herons working the fish-farm cages. This is the slow afternoon most visitors never find.",story:"Begnas does not perform for anyone. Row out from the ghat by the dam and the sounds are paddle-drips, kingfishers, and farmers calling across paddy terraces that run straight down to the shore. The lake's cage farms raise carp, which is why herons and egrets stake out the floating frames, and why the lakeside kitchens serve fish fresh enough to argue about. Sundari Danda rises green across the water, and on a clear day Machapuchare shows over the ridgeline.",includes:["Wooden boat hire, rowed or self-paddled","Life jackets for everyone aboard","A slow lap past the cage farms and the quiet east shore","Optional boatman who knows the bird corners"],goodToKnow:"Getting there is half the outing: allow about an hour from Lakeside by taxi or local bus. Weekends draw Pokhara picnickers to the ghat; weekday afternoons are all yours.",whatThisIsNot:"This is not a sight to tick off: there is no island shrine and nothing to queue for, and an outboard wake is rare enough to count as an event.",meetPoint:"Begnas boat ghat, Begnas Bazar",fitness:"any",operatorId:"op-rivers",bestMonths:"Year-round (clearest Oct–Apr)",palette:"lake",lat:28.17,lng:84.1},{slug:"karnali-mahseer-fishing",name:"Mahseer fishing, Karnali",location:"Karnali and Babai rivers, Bardiya",category:"water",world:"water",duration:"4 days",priceFromNpr:58e3,blurb:"The golden mahseer is the Himalaya's great river fish, and the Karnali's confluences are where anglers come to meet one. Days of wild water on the edge of Bardiya, every fish photographed and released.",story:"Camps work the junction pools where the Babai and Karnali gather their tributaries along the Bardiya border, water the colour of bottle glass sliding out of the last hills. Golden mahseer hold in the seams and take spinners and flies with a first run that explains their reputation. Between sessions the jungle comes to the bank: chital drinking at dusk, elephant tracks in the sand, and sometimes a Gangetic dolphin rolling in the deep water below Chisapani. Everything caught goes back.",includes:["Experienced fishing guides and riverside camp","Rods, reels and lures, or bring your own kit","All meals and tents at the confluence camps","Fishing permits and a catch-and-release briefing"],goodToKnow:"Mahseer fishing is patient fishing: takes come in bursts around dawn, dusk and changing water. It is strictly catch and release on barbless hooks, and the camp photographs and returns every fish.",whatThisIsNot:"This is not a guaranteed trophy: mahseer are wild, moody and declining across their range, and a blank day beside a river full of birds is a real possibility.",meetPoint:"Thamel departure point, Kathmandu",fitness:"any",operatorId:"op-rivers",bestMonths:"Feb–Apr · Oct–Nov",palette:"forest",lat:28.64,lng:81.28},{slug:"bardiya-tiger-safari",name:"Bardiya tiger safari",location:"Bardiya National Park",category:"wildlife",world:"wild",duration:"2 days",priceFromNpr:16500,blurb:"Nepal's best tiger odds, earned the old way: on foot and by jeep in the far-western sal forest, behind a guide who reads river sand like a morning paper.",story:"Bardiya is what Chitwan was a generation ago: sal forest and grassland along the Geruwa branch of the Karnali, far enough west that jeeps are scarce and phone signal gives up. Your naturalist tracks the slow way, reading pugmarks in river sand and waiting downwind while chital alarm calls map a predator you cannot yet see. On foot you move in single file behind two trained guides; in the jeep, engines cut the moment anything shows. Every approach keeps a strict distance, and the tiger decides the rest.",includes:["Park entry permits and buffer-zone fees","Licensed naturalist plus a second walking guide","Walking safari and jeep safari in the core park","Lodge night and meals in Thakurdwara"],goodToKnow:"A tiger is luck even here; most days give deer, wild boar and fresh pugmarks. The prime months are seriously hot, past 40°C by May, so walks run at dawn and dusk. Leeches arrive with the first pre-monsoon storms. Park-approved operators only, never elephant-back.",whatThisIsNot:"This is not a drive-through zoo: a tiger day is earned in silence at a strict distance, and often ends with only pugmarks.",meetPoint:"Thakurdwara gate, Bardiya",fitness:"active",operatorId:"op-wild",bestMonths:"Feb–Jun",palette:"forest",lat:28.43,lng:81.2},{slug:"koshi-tappu-birdwatching",name:"Koshi Tappu birdwatching",location:"Koshi Tappu Wildlife Reserve, Sunsari",category:"wildlife",world:"wild",duration:"Full day",priceFromNpr:7500,blurb:"A dawn-to-dusk watch on the Sapta Koshi floodplain, where the reed beds hold more than 500 recorded species and the islands belong to the arna, Nepal's last wild water buffalo.",story:"Koshi Tappu is Nepal's first Ramsar wetland, a braid of channels, mudflats and reed beds behind the Koshi Barrage. Winter mornings stack the sky with waterfowl down from Tibet and Siberia; by mid-morning your guide is picking swamp francolins out of the grass by call alone. The reserve's arna, the last wild water buffalo in Nepal, graze the islands and are watched from a respectful distance. Walks follow the embankments, a canoe crosses the quieter channels, and the list grows all day.",includes:["Reserve entry permit","Specialist birding guide with a spotting scope","Embankment walks and a canoe crossing","Reserve bird checklist to keep"],goodToKnow:"Winter fog can sit on the barrage until mid-morning; the birding stays good while the photography waits. Guides keep a hard distance from the arna herds, which are wild and short-tempered. Bring binoculars if you own them; loaner pairs are basic.",whatThisIsNot:"This is not a tick-list machine: the wetland decides the day, a shifted channel can move the birds a kilometre overnight, and the rarest residents stay deep in the grass.",meetPoint:"Koshi Tappu reserve HQ, Sunsari",fitness:"any",operatorId:"op-wild",bestMonths:"Oct–Mar",palette:"forest",lat:26.63,lng:86.99},{slug:"shuklaphanta-safari",name:"Shuklaphanta grasslands safari",location:"Shuklaphanta National Park, Kanchanpur",category:"wildlife",world:"wild",duration:"Full day",priceFromNpr:8500,blurb:"The far west at first light: a phanta so wide it swallows the jeep, grazed by the largest swamp deer herds in Nepal.",story:"Phanta is the Tharu word for grassland, and Shuklaphanta is the biggest one Nepal has, an open sweep in the far-western corner past Mahendranagar. Its swamp deer, the barasingha, gather here in the largest herds in the country; rutting stags carry twelve-tined antlers and call across the grass at dusk. A jeep runs the phanta edge and the sal forest tracks, stopping at Rani Tal, where mugger crocodiles lie out on the banks. Tigers patrol here too, seen rarely, read daily in the dust of the fire lines.",includes:["Park entry permit","Licensed naturalist guide","Jeep for the phanta and sal forest tracks","Packed lunch on the grassland edge"],goodToKnow:"It is a long way west: most people fly to Dhangadhi and drive on, or come overland from Bardiya. The deer are reliable, the tiger is not. Park-approved jeeps only, engines off at sightings, never elephant-back.",whatThisIsNot:"This is not a park you stumble into: the far west costs a full travel day each way, and the phanta pays you back in space, not certainty.",meetPoint:"Majhgaun gate, Kanchanpur",fitness:"any",operatorId:"op-wild",bestMonths:"Oct–Mar",palette:"forest",lat:28.84,lng:80.24},{slug:"rapti-canoe-float",name:"Rapti canoe float",location:"Rapti River, Sauraha, Chitwan",category:"wildlife",world:"wild",duration:"2 hours",priceFromNpr:2e3,blurb:"A dawn drift down the Rapti in a carved dugout, past gharial warming their needle snouts on the sandbars.",story:"You push off from Sauraha ghat while the Rapti is still smoking with mist, in a dugout cut from a single silk-cotton trunk. The boatman poles; nobody talks. Gharial lie on the sandbars with their needle snouts agape to warm up, and mugger crocodiles sit lower in the murk, all eyes. Kingfishers work the banks, ruddy shelducks argue midstream, and sometimes a rhino stands in the current ahead, in which case the boatman waits. The float ends in the buffer zone with a short walk back.",includes:["Buffer-zone entry fee","Dugout canoe with an experienced boatman","Naturalist guide on board","Guided walk back along the bank"],goodToKnow:"Winter dawns on the water are cold; bring a layer for the first hour. Gharial are close to reliable in the dry months, a rhino at the water's edge is a bonus, never a promise. Life jackets provided and worn.",whatThisIsNot:"This is not a paddle sport: you sit low and still while the boatman poles, and he, not you, sets the distance from every crocodile and rhino.",meetPoint:"Sauraha ghat, Chitwan",fitness:"any",operatorId:"op-wild",bestMonths:"Oct–Mar",palette:"dawn",lat:27.57,lng:84.49},{slug:"chitwan-tower-night",name:"Chitwan tower night",location:"Chitwan buffer forest, Sauraha",category:"wildlife",world:"wild",duration:"Overnight",priceFromNpr:9500,blurb:"A night in a machan above a buffer-forest waterhole, where the jungle arrives as sound long before you see anything.",story:"Machans are the Terai's old crop-guarding towers, and Baghmara's community buffer forest keeps a few for guests. You walk in before dusk with a naturalist, climb the ladder, and the day shift hands over. Night work is listening: chital bark their sharp alarm when a predator moves, langurs cough in the canopy, a nightjar churrs from the track below. A torch sweep of the waterhole can catch eyeshine, deer or civet or, on a lucky night, rhino. Dawn comes with a mist walk out.",includes:["Community-forest entry and machan fee","Naturalist who stays the night with you","Dinner, breakfast and bedding","Dawn walk back through the buffer forest"],goodToKnow:"It is deliberately basic: bedding on a wooden platform, a ground-level squat toilet, no power. Cold in December and January, loud with insects after the first rains, and what visits the waterhole is luck.",whatThisIsNot:"This is not staged wildlife: nothing is baited or driven towards the tower, some nights pass quiet, and the offer is the dark itself, heard properly for once.",meetPoint:"Sauraha park gate, Chitwan",fitness:"any",operatorId:"op-wild",bestMonths:"Oct–Mar",palette:"forest",lat:27.55,lng:84.45},{slug:"momo-masterclass",name:"Momo masterclass",location:"Thamel, Kathmandu",category:"culture",world:"sacred",duration:"3 hours",priceFromNpr:3500,blurb:"Fold, pleat and steam your way through Nepal's favourite dumpling with a Thamel home cook, then eat your homework with a chutney you ground yourself.",story:"Momos are Nepal's common language, and this class teaches you to speak it. Around a courtyard table you knead the dough, spice the filling two ways (buff and vegetable), and learn the twelve-pleat fold from a host who has made them since childhood. While the steamers work, you grind sesame and tomato into achar. Then the best part: you eat everything, seconds encouraged.",includes:["All ingredients and a courtyard cooking station","Two fillings and the classic sesame-tomato achar","Your host's family pleating technique","Dinner is what you made, with seconds"],goodToKnow:"Hands-on and flour-dusted; vegetarian fillings are always available. Classes run morning and late afternoon, six seats each.",whatThisIsNot:"This is not a restaurant demo: you cook everything yourself, your first pleats will tear, and dinner is whatever you make of it.",meetPoint:"Basecamp Thamel courtyard",fitness:"any",operatorId:"op-basecamp",bestMonths:"Year-round",palette:"day",lat:27.7154,lng:85.3123},{slug:"thamel-heritage-walk",name:"Thamel heritage walk",location:"Thamel and old Kathmandu",category:"culture",world:"sacred",duration:"2.5 hours",priceFromNpr:2800,blurb:"Step out of the souvenir strip into the courtyards behind it: hidden stupas, a fifteenth century bahal, and the Asan morning market where Kathmandu actually shops.",story:"Ten metres behind Thamel's shopfronts the old city keeps its own hours. A host from the neighbourhood walks you through carved courtyards the guidebooks skip, past a stupa that predates the tourist quarter by five centuries, and into the spice-and-marigold crush of Asan's morning market. You end with milk tea where the porters take theirs, knowing how to read a bahal doorway for the rest of your trip.",includes:["Local host from the neighbourhood","Asan and Indra Chowk morning market","Three hidden bahals and a living stupa","Milk tea stop, on us"],goodToKnow:"Mornings are best: the market peaks before nine and the courtyards stay quiet. Wear shoes you trust on worn brick.",whatThisIsNot:"This is not a shopping tour: the point is the ten metres behind the shopfronts, where the old city keeps its own hours.",meetPoint:"Basecamp Thamel courtyard",fitness:"any",operatorId:"op-basecamp",bestMonths:"Year-round",palette:"day",lat:27.7135,lng:85.3105},{slug:"bhaktapur-pottery-workshop",name:"Bhaktapur pottery workshop",location:"Pottery Square, Bhaktapur",category:"culture",world:"sacred",duration:"3 hours",priceFromNpr:2800,blurb:"Sit at a wheel in Pottery Square while a Prajapati potter steadies your hands until a lump of black clay becomes a pot. It is fired and yours to keep.",story:"Bhaktapur's Pottery Square still works the way it looks: rows of pots drying in the sun, straw-fired kilns smoking at the edge, and the Prajapati families who have thrown clay here for generations. You take a wheel beside them, learn to centre the black valley clay (harder than it looks), and shape a small pot or oil lamp with a potter's hands guiding yours. Around you the square keeps working: wedging, trimming, stacking, and the slap of clay on the wheelhead.",includes:["A wheel, clay and an apron in the working square","A Prajapati family potter as your teacher","Firing in the straw kiln","Your pot, collected or sent on to Kathmandu"],goodToKnow:"Clay gets everywhere; wear clothes you can wash. Firing takes a day or two, so you collect your pot later or have it sent to your Kathmandu hotel.",whatThisIsNot:"This is not a paint-a-pot cafe: the wheel fights back, first attempts collapse, and the potters will have you start again until one stands true.",meetPoint:"Pottery Square, Bhaktapur",fitness:"any",operatorId:"op-heritage",bestMonths:"Year-round",palette:"alpenglow",lat:27.671,lng:85.428},{slug:"lumbini-pilgrimage",name:"Lumbini day pilgrimage",location:"Lumbini, Rupandehi",category:"culture",world:"sacred",duration:"Full day",priceFromNpr:8500,blurb:"Stand at the spot where tradition places the Buddha's birth. You cover the Maya Devi temple, the Ashoka pillar and the canal-side monastic zone by bicycle, at pilgrim pace.",story:"Lumbini is quiet in a way that carries. At its centre the Maya Devi temple shelters the marker stone of the Buddha's birthplace, beside a pillar the emperor Ashoka raised in 249 BC to say he had been here too. Around it, a long garden of monasteries built by Buddhist nations spreads along a canal, best covered by bicycle. A local guide walks you through the archaeology in the morning; the afternoon is yours to sit under the Bodhi tree with the pilgrims.",includes:["Guide for the Maya Devi temple and Ashoka pillar","Bicycle hire for the monastic zone","Sacred garden entry fees","Return transfer from Bhairahawa"],goodToKnow:"Shoes off and shoulders covered at the Maya Devi temple. The Terai is seriously hot from April to June; start early and drink more water than feels reasonable.",whatThisIsNot:"This is not a single monument stop: the sacred garden runs flat for kilometres, and skipping the bicycle means a long day of walking in open Terai sun.",meetPoint:"Bhairahawa airport pickup",fitness:"any",operatorId:"op-heritage",bestMonths:"Year-round",palette:"dawn",lat:27.469,lng:83.276},{slug:"janakpur-mithila-art",name:"Janakpur and Mithila art",location:"Janakpur, Dhanusha",category:"culture",world:"sacred",duration:"Full day",priceFromNpr:7500,blurb:"Janakpur paints its stories on its walls. Spend the day between the Janaki Mandir's marble courtyards and the women's cooperative that carried Mithila painting from mud walls to the world, brush in hand by afternoon.",story:"Hindu tradition marries Ram and Sita in Janakpur, and the Janaki Mandir, a white marble palace of a temple, marks it. That is the morning. The afternoon belongs to the painters: at the Janakpur Women's Development Centre, Maithil women turn the wedding and harvest scenes their mothers drew on courtyard walls into paper, textiles and ceramics that now sell worldwide. They will sit you down with a brush and a wall section of your own, and correct your peacocks kindly.",includes:["Janaki Mandir visit with a local guide","Afternoon at the Mithila painting cooperative","Your own wall section, paints supplied","Maithili thali lunch"],goodToKnow:"Janakpur is a flat, loud Terai town and proud of it; the temple asks for covered shoulders, and the midday heat is serious from April onward.",whatThisIsNot:"This is not a gallery visit: the cooperative is a working studio where orders come first, and your own painting will look like a first attempt because it is one.",meetPoint:"Janakpur station",fitness:"any",operatorId:"op-heritage",bestMonths:"Year-round",palette:"day",lat:26.729,lng:85.925},{slug:"gorkha-durbar-day",name:"Gorkha Durbar day",location:"Gorkha Durbar, Gorkha",category:"culture",world:"sacred",duration:"Full day",priceFromNpr:6500,blurb:"Every unification story starts somewhere; Nepal's starts on this hilltop. Climb the long stone staircase to the fortress-palace of Prithvi Narayan Shah, with the Manaslu range standing behind it on a clear day.",story:"Gorkha Durbar is where the Shah dynasty set out to stitch dozens of hill kingdoms into one Nepal, and the palace has not moved an inch to meet its visitors: roughly 1,700 stone steps climb from the bazaar to the ridge. At the top, a Malla-era palace, the Gorakhnath cave shrine and the Kalika temple share the spine of the hill, with drums sounding on worship days. A guide fills in the eighteenth-century campaign on the way up, between breathers.",includes:["Return transport from Kathmandu","Historian guide for the palace and shrines","Kalika temple and Gorakhnath cave visit","Lunch in Gorkha bazaar"],goodToKnow:"About an hour of stone steps each way with no vehicle road to the top; carry water and start early in warm months. The Kalika temple interior admits only its priests, so you worship from the threshold like everyone else.",whatThisIsNot:"This is not a drive-up viewpoint: the steps are the only way in, and haze can keep the Manaslu backdrop out of sight while the climb stays entirely real.",meetPoint:"Your Kathmandu hotel lobby",fitness:"active",operatorId:"op-heritage",bestMonths:"Year-round",palette:"dusk",lat:28.001,lng:84.632},{slug:"bandipur-old-town",name:"Bandipur old town",location:"Bandipur, Tanahun",category:"culture",world:"sacred",duration:"Half day",priceFromNpr:3500,blurb:"A bazaar town on a saddle ridge that banned cars from its main street and kept its silk-route houses instead. Half a day of slate paving, carved windows and long Himalayan views.",story:"Bandipur was a Newar trading town on the India to Tibet route until the highway moved downhill and took the traffic with it, which is why the architecture survived. The main bazaar is car-free and paved in slate, lined with tall shuttered merchant houses their owners never had reason to demolish. You walk it with a local host: the Bindyabasini temple, the sweet stalls, then the short climb to the Tundikhel parade ground, where the Marsyangdi valley drops away and the Himalaya stands up on a clear morning.",includes:["Local host for the bazaar and temples","Bindyabasini and Khadga Devi temple visits","Tundikhel ridge viewpoint walk","Tea and sel roti in the bazaar"],goodToKnow:"Vehicles stop at the edge of town; everything else is on foot over slate and steps. Mornings are clearest for the mountain line; by noon the haze usually wins.",whatThisIsNot:"This is not a preserved film set: people live, trade and go to school here, and the car ban ends at the bazaar's edge where the jeeps wait.",meetPoint:"Bandipur bus park",fitness:"any",operatorId:"op-heritage",bestMonths:"Year-round",palette:"day",lat:27.938,lng:84.407},{slug:"tansen-heritage-walk",name:"Tansen heritage walk",location:"Tansen, Palpa",category:"culture",world:"sacred",duration:"Half day",priceFromNpr:3800,blurb:"Palpa's old hill capital keeps its crafts within a few steep lanes. Dhaka cloth on the looms, karuwa brass under the hammers, and the story of a ruined river palace to send you onward.",story:"Tansen was the seat of the Sen kings and then a Rana governor's posting, and its steep cobbled lanes still work for a living. A local host takes you through Sitalpati's octagonal pavilion square, into workshops hammering karuwa water jugs from brass, and past looms weaving Palpali dhaka in patterns this town made famous. You finish at the Amar Narayan temple with a talk on Ranighat, the 1893 palace a governor built for his wife on the Kali Gandaki, a half-day walk below town if you stay on.",includes:["Local host through the old bazaar lanes","Dhaka weaving and karuwa brass workshops","Amar Narayan temple and Sitalpati square","Route notes for the Ranighat walk"],goodToKnow:"Tansen is built on a hillside; every lane is a stair in disguise. The Ranighat palace itself is a separate half-day round trip on foot, not part of this walk.",whatThisIsNot:"This is not a curated craft village: the workshops are working businesses that close for festivals and funerals, and the lanes are steep enough to count as exercise.",meetPoint:"Sitalpati, Tansen",fitness:"any",operatorId:"op-heritage",bestMonths:"Year-round",palette:"forest",lat:27.867,lng:83.547},{slug:"panauti-kirtipur-day",name:"Panauti and Kirtipur day",location:"Panauti & Kirtipur",category:"culture",world:"sacred",duration:"Full day",priceFromNpr:5500,blurb:"Two Newar towns the tour buses mostly skip: Panauti at its sacred river confluence, Kirtipur on its defiant hilltop. One day, two different answers to how old towns stay alive.",story:"Panauti sits where two rivers meet (a third, invisible one joins them, locals say) and its Indreshwar temple has stood over the confluence since the thirteenth century, one of the oldest pagoda roofs in Nepal. Kirtipur, the afternoon, is the hill town that held off Prithvi Narayan Shah's army through repeated sieges before the valley fell. You walk both with a Newar guide, eat in a Kirtipur kitchen where the bara comes off the griddle in front of you, and learn why neither town ever needed to become a museum.",includes:["Private transport linking both towns","Newar guide for temples and backstreets","Indreshwar temple and the Panauti ghats","Newari lunch in Kirtipur"],goodToKnow:"Panauti's riverside ghats are a cremation and ritual site; keep a respectful distance when ceremonies are under way. Kirtipur's lanes are steep and stepped.",whatThisIsNot:"This is not Bhaktapur without the crowds: both towns are smaller and rougher at the edges, and some courtyards still wear props and scaffolding from the 2015 earthquake.",meetPoint:"Your Kathmandu hotel lobby",fitness:"any",operatorId:"op-heritage",bestMonths:"Year-round",palette:"day",lat:27.585,lng:85.508},{slug:"ghale-gaun-homestay",name:"Ghale Gaun homestay",location:"Ghale Gaun, Lamjung",category:"culture",world:"sacred",duration:"2 days",priceFromNpr:9500,blurb:"Sleep in a Gurung house in the village Nepal points to when it explains what a homestay should be. Lamjung Himal fills the window before your tea does.",story:"Ghale Gaun, two hours of rough road above Besisahar, organised itself into a community homestay years before the idea was fashionable, and it shows: each slate-roofed house takes guests in turn, so the income reaches the whole village. You are met with marigold garlands, fed dal bhat by your host family, and pulled into the evening's Gurung song and dance whether you can dance or not. At first light, Lamjung Himal and Annapurna II stand straight across the valley from the breakfast terrace.",includes:["Jeep from Besisahar and back","One night with a Gurung host family","All meals, cooked in the house","Evening community song and dance"],goodToKnow:"Bathrooms are shared and hot water arrives by bucket; bedding is thick and clean. The road up from Besisahar is rough jeep track, slower again after rain.",whatThisIsNot:"This is not a hotel with village styling: you live on the family's clock, dinner is what the kitchen cooks, and the door between you and the household is often a curtain.",meetPoint:"Besisahar jeep stand",fitness:"any",operatorId:"op-heritage",bestMonths:"Oct–Apr",palette:"dawn",lat:28.37,lng:84.42},{slug:"ghandruk-homestay",name:"Ghandruk homestay",location:"Ghandruk, Kaski",category:"culture",world:"sacred",duration:"2 days",priceFromNpr:8500,blurb:"A stone-and-slate Gurung village in the Annapurna foothills, big enough for a museum and its own weaving looms, small enough that your host knows every roof. Machapuchare watches the whole stay.",story:"Ghandruk is the great Gurung village of the Annapurna foothills, stone houses stacked over flagstone lanes at about 2,000 metres, a day's walk or a rough jeep ride up from Nayapul. Trekkers pass through on the Poon Hill and Base Camp trails; staying puts you on the other side of the window. Your host family cooks on the wood stove, the old Gurung museum keeps the shepherd kit and army photographs of the grandparents, and weavers work wool into radi blankets on looms in the lanes.",includes:["One night with a Gurung host family","All meals from the family kitchen","Gurung museum entry and a loom visit","Sunrise walk to the village viewpoint"],goodToKnow:"Ghandruk sits inside the Annapurna Conservation Area, so the ACAP entry permit applies; we arrange it with the booking. Bathrooms are mostly shared and nights turn cold from late autumn.",whatThisIsNot:"This is not a remote discovery: Ghandruk is on a busy trekking trail with wifi and espresso in season, and the point of staying is depth, not distance.",meetPoint:"Nayapul roadhead, Pokhara",fitness:"any",operatorId:"op-heritage",bestMonths:"Oct–Apr",palette:"forest",lat:28.376,lng:83.81},{slug:"tihar-festival-evening",name:"Tihar festival evening",location:"Old Kathmandu",category:"culture",world:"sacred",duration:"3 hours",priceFromNpr:3200,blurb:"For five nights each autumn Kathmandu lays paths of marigold and lamplight to its own doors. Walk into the middle of it while deusi-bhailo singers work the neighbourhood.",story:"Tihar honours crows, dogs, cows and finally brothers, one day at a time, and the city answers with oil lamps on every sill, mandalas of coloured powder at every threshold, and marigolds strung by the kilometre. On the walk a local host decodes it: why the dogs wear tika today, which doorstep pattern welcomes Laxmi, and how the deusi-bhailo teams trade songs for coins and sel roti. You end on a rooftop above the old town with the lamps spread below.",includes:["Local host for the evening","Old-town route past the lit thresholds","Deusi-bhailo stops with a neighbourhood team","Rooftop finish above the lamplit old town"],goodToKnow:"We confirm exact festival evenings about two months out, once the lunar calendar is fixed. Firecrackers are part of the soundtrack, and some lanes get smoky.",whatThisIsNot:"This is not an illuminations tour with a set route: the songs move house to house at their own pace, and the best courtyard of the night cannot be booked in advance.",meetPoint:"Your Kathmandu hotel lobby",fitness:"any",operatorId:"op-heritage",bestMonths:"Oct–Nov (festival dates move with the lunar calendar)",palette:"night",lat:27.704,lng:85.307},{slug:"indra-jatra-experience",name:"Indra Jatra with a historian",location:"Basantapur, Kathmandu",category:"culture",world:"sacred",duration:"3 hours",priceFromNpr:3500,blurb:"Once a year the living goddess leaves her house and Kathmandu pulls her chariot through streets built for it. Stand in the right place with someone who knows what you are seeing.",story:"Indra Jatra is eight days of masked dance and ritual, and its centre is the evening the Kumari's chariot runs from Basantapur through the old city, preceded by the chariots of Ganesh and Bhairab, cleared by lakhe dancers in red masks. A historian keeps you at the edges with sightlines: the lingo pole, the Seto Bhairab head pouring rice beer through a spout for the crowd, the corner where the chariot turns and the pullers strain. You are a guest at a ritual, not an audience at a show.",includes:["Historian host for the evening","Positioned viewpoints along the chariot route","The lingo pole and Seto Bhairab explained","Tea stop while the crowd peaks"],goodToKnow:"Dates follow the lunar calendar and firm up close to the festival; the group is capped at six so we can move through the crowd. Wear closed shoes and carry nothing you would mind losing.",whatThisIsNot:"This is not a staged show: Indra Jatra is a real crowd with real crush points, and the Kumari appears when the ritual says so, not when the itinerary does.",meetPoint:"Basantapur Durbar Square gate",fitness:"any",operatorId:"op-heritage",bestMonths:"Sep (dates move with the lunar calendar)",palette:"dusk",lat:27.704,lng:85.307},{slug:"thangka-painting-workshop",name:"Thangka painting workshop",location:"Boudha, Kathmandu",category:"culture",world:"sacred",duration:"Half day",priceFromNpr:4500,blurb:"Sit at a slanted board in a Boudha studio while a lineage painter shows you why a single deity can take three months. You gild a small mandala of your own.",story:"Thangka painting is devotion with a brush: cotton stretched and primed, deities laid out on strict grids, mineral pigments ground by hand, gold last of all. In a studio near the Boudha stupa, a Tamang painter who learned the craft from his father walks you through the iconography, then sets you up with a pre-sketched mandala, fine brushes and real gold to gild the border. You leave with your practice piece and a sharper eye: after this, you can tell a painted thangka from a printed one across a shop.",includes:["A bench in a working thangka studio","Materials: canvas board, pigments, gold","Your gilded practice mandala to keep","Tea with the painters"],goodToKnow:"This is close, detailed work under good light; bring reading glasses if you use them. The studio sells finished thangkas, with no pressure attached to the class.",whatThisIsNot:"This is not a certificate course: one sitting buys you respect for the craft and one gilded border, not the craft itself.",meetPoint:"Boudha stupa north gate",fitness:"any",operatorId:"op-heritage",bestMonths:"Year-round",palette:"alpenglow",lat:27.721,lng:85.362},{slug:"singing-bowl-sound-bath",name:"Singing bowl sound bath",location:"Boudha, Kathmandu",category:"culture",world:"sacred",duration:"90 minutes",priceFromNpr:2500,blurb:"Lie down under seven bowls in a Boudha studio and let a practitioner play them in sequence, struck and rimmed. The sound arrives in the sternum before it reaches the ears.",story:"The room is a lane back from the Boudha stupa, close enough that the murmur of the evening kora leaks in under the door. You lie on a mat, blanket over you, and hand-beaten bronze bowls are set around and on your body. The practitioner works through them in sequence, striking some, rimming others so the overtones cross and beat. Most people drop into a state between sleep and listening; a few just get a very good rest. It ends with tea and no obligation to explain yourself.",includes:["Private mat, bolster and blanket","A full bowl sequence, struck and rimmed","Quiet room a lane off the stupa","Herbal tea after"],goodToKnow:"Wear loose clothes and skip the heavy meal beforehand. The bowls rest on the body; tell the practitioner about pregnancy, pacemakers or recent surgery and they will adapt the layout.",whatThisIsNot:"This is not a medical treatment: the studio makes no healing claims, and if you fall asleep and snore through the finale, that counts as success.",meetPoint:"Boudha stupa north gate",fitness:"any",operatorId:"op-heritage",bestMonths:"Year-round",palette:"lake",lat:27.721,lng:85.362},{slug:"pokhara-yoga-retreat",name:"Pokhara yoga retreat",location:"Lakeside, Pokhara",category:"culture",world:"calm",duration:"3 days",priceFromNpr:18500,blurb:"Lakeside days that run to the body's clock: pranayama as the mist lifts off Phewa, a second practice at dusk, and food picked from the garden in between.",story:"The retreat sits above Phewa Lake at the quiet north end of Lakeside, where the day starts with pranayama on a platform facing the water. Morning practice is slow and structural, the dusk session softer, and between them you eat what the garden grows: saag, pumpkin, coriander pulled an hour before lunch. On clear mornings Machapuchare stands upside down in the lake while you breathe. Nothing is compulsory. Sleep, swim, read. The schedule holds you without gripping.",includes:["Two guided practices daily plus dawn pranayama","Simple room and vegetarian meals from the garden","Mats, props and a practice platform over the lake","Free hours built into every afternoon"],goodToKnow:"Rooms are simple, hot water is solar and runs short on cloudy days, and the platform is cold enough for a blanket until the sun clears the ridge.",whatThisIsNot:"This is not a luxury spa retreat: the discipline is gentle but real, phones stay quiet in shared spaces, and the entertainment is the lake.",meetPoint:"Lakeside north, Pokhara",fitness:"any",operatorId:"op-heritage",bestMonths:"Oct–Apr",palette:"dawn",lat:28.21,lng:83.96},{slug:"kathmandu-rim-yoga",name:"Kathmandu rim yoga day",location:"Nagarkot, Kathmandu Valley rim",category:"culture",world:"calm",duration:"Full day",priceFromNpr:6500,blurb:"Trade the city's horns for a ridge-top shala: a long morning practice, a pine forest walk, and the valley haze turning gold at sunset.",story:"The ridge at Nagarkot stands a winding hour and a half above the traffic, high enough that pines replace horns. The day is built like a slow exhale: a long morning asana practice in a glass-sided shala, dal bhat for lunch, then a forest walk where the resin smell does half the work. A restorative session closes the mat time before the ridge delivers its finale: valley haze turning amber over the terraces, and on clear evenings the Langtang peaks lining the northern horizon.",includes:["Return transport from Kathmandu","Morning asana and late restorative sessions","Vegetarian dal bhat lunch at the retreat","Guided pine forest walk on the rim path"],goodToKnow:"Sunset is a lottery: spring haze can flatten the view for days, and winter evenings on the ridge turn cold fast once the sun goes.",whatThisIsNot:"This is not a mountain panorama on demand: Nagarkot's famous horizon needs clear air, and the practice has to be worth the day on its own.",meetPoint:"Nagarkot bus park",fitness:"any",operatorId:"op-heritage",bestMonths:"Oct–Apr",palette:"dusk",lat:27.72,lng:85.52},{slug:"kopan-meditation-course",name:"Kopan Monastery meditation",location:"Kopan hill, Kathmandu",category:"culture",world:"calm",duration:"2 days",priceFromNpr:7500,blurb:"Sleep inside a working Gelug monastery above Boudha, wake to the gong, and let monks walk you through the first steps of watching your own mind.",story:"Kopan has taught meditation to visitors since the 1970s, and it wears the routine lightly. You sleep in a plain guest room on the hill above Boudha, and before first light a gong sounds down the corridors: not an alarm, an invitation. Monks lead sittings in the gompa, explain the analytical meditations of the Gelug tradition in plain English, and take questions that have no easy answers. Between sessions you drink milk tea on the wall and watch the valley wake beneath the prayer flags.",includes:["Guest room and vegetarian meals on the hill","Guided sittings and teachings led by monks","Walking meditation in the monastery gardens","Question time with a senior teacher"],goodToKnow:"The fee covers your food and lodging; monastery teachings run on dana, so bring cash for a donation at the end and give what feels right. Silence holds until after breakfast.",whatThisIsNot:"This is not a wellness weekend: beds are hard, the gong comes before dawn, and the teaching asks you to examine your mind rather than empty it.",meetPoint:"Kopan gate, Kathmandu",fitness:"any",operatorId:"op-heritage",bestMonths:"Year-round",palette:"day",lat:27.74,lng:85.36},{slug:"vipassana-orientation",name:"Vipassana orientation day",location:"Budhanilkantha, Kathmandu",category:"culture",world:"calm",duration:"1 day",priceFromNpr:2500,blurb:"A silent-practice taster on Kathmandu's forested northern edge, with old students on hand to explain what the full course asks before you commit to it.",story:"Dharmashringa, the Vipassana centre in the S.N. Goenka tradition, sits on the wooded slope above Budhanilkantha, and this day is the honest doorway to it. Old students walk you through the technique's logic, the code of discipline, and what a morning of noble silence actually feels like: just breath, the itch you do not scratch, crows in the forest outside. You sit twice, eat a simple vegetarian lunch, and leave with the application process demystified.",includes:["Introduction to the technique and code of discipline","Two guided silent sittings","Simple vegetarian lunch","Alumni guidance on applying for the full course"],goodToKnow:"Wear loose clothes and expect cushions on the floor; chairs exist, but the point is learning to be still. Phones stay in a locker for the day.",whatThisIsNot:"This is not the real thing, and does not pretend to be: the full ten-day Vipassana courses are free, run on donations, and are booked out months ahead. This day exists to help you decide and apply.",meetPoint:"Budhanilkantha temple gate, Kathmandu",fitness:"any",operatorId:"op-heritage",bestMonths:"Year-round",palette:"forest",lat:27.78,lng:85.36},{slug:"ayurveda-treatment-day",name:"Ayurveda treatment day",location:"Kathmandu",category:"culture",world:"calm",duration:"Half day",priceFromNpr:9500,blurb:"A pulse-read consultation, warm oil worked into every joint, and the slow thread of shirodhara across your forehead: the old medicine of the subcontinent, taken seriously.",story:"The clinic runs on a rhythm older than the city around it. A physician takes your pulse and history first, because the treatments are adjusted to you rather than sold off a menu. Then abhyanga: warm sesame-based oil worked in long strokes until your joints stop reporting in. The centrepiece is shirodhara, a thin unbroken line of warm oil poured slowly across the forehead until time goes soft. Most people cross into something that is not quite sleep. You leave oiled, slow, and under orders to rest.",includes:["Consultation with an Ayurvedic physician","Abhyanga full-body warm oil massage","Shirodhara oil-stream treatment","Herbal tea and rest time afterwards"],goodToKnow:"Your hair will be soaked in oil, so plan a slow evening rather than a flight or a trek departure. Tell the physician about any medication at the consultation.",whatThisIsNot:"This is not a hotel spa with Ayurvedic branding: the clinic is clinical, the oil gets everywhere, and the physician may tell you things about your routine you did not ask to hear.",meetPoint:"Clinic reception, Kantipath, Kathmandu",fitness:"any",operatorId:"op-heritage",bestMonths:"Year-round",palette:"lake",lat:27.71,lng:85.32},{slug:"tatopani-hot-springs",name:"Tatopani hot springs",location:"Tatopani, Kali Gandaki valley",category:"culture",world:"calm",duration:"Half day",priceFromNpr:1500,blurb:"Tatopani means hot water in Nepali, and the village delivers exactly that: steaming riverside pools where trekkers' legs have been recovering for decades.",story:"Tatopani sits low in the Kali Gandaki gorge on the old Annapurna Circuit trail, and its name is a plain description: hot water. The pools are simple concrete tanks by the river, fed by a spring that comes out steaming, and the ritual is unchanged: ease in, gasp, go still. Around you are trekkers comparing knees, local families on an outing, and steam drifting against the gorge wall. The mineral smell of the water stays on your skin for the rest of the day.",includes:["Pool entry fee","Locker and changing shed","Milk tea at a gorge-side lodge afterwards"],goodToKnow:"The pools are communal and simple: modest swimwear, a basic changing shed, and busy evenings when trekking groups roll in. The spring runs hot, so enter slowly.",whatThisIsNot:"This is not a spa in the resort sense: Tatopani is two concrete pools by a working road, and that is its charm.",meetPoint:"Tatopani bus stop, Beni road",fitness:"any",operatorId:"op-heritage",bestMonths:"Oct–Apr",palette:"dawn",lat:28.49,lng:83.65},{slug:"jhinu-danda-hot-springs",name:"Jhinu Danda hot springs",location:"Jhinu Danda, Modi Khola valley",category:"culture",world:"calm",duration:"Full day",priceFromNpr:4500,blurb:"Walk in from the Ghandruk side, drop the stone staircase to the Modi Khola, and earn the steaming pools the way trekkers do: on foot.",story:"The springs below Jhinu Danda ask for a walk first, which is the point. From the Ghandruk side the trail contours through millet terraces and rhododendron, then drops a long stone staircase to the banks of the Modi Khola, where stone-walled pools steam beside the grey glacial river. The soak lands differently on tired legs. You hear the river the whole time, loud and cold a metre away, while the spring holds you at bath temperature. Climb back up for dal bhat in the village before the walk out.",includes:["Local guide for the walking day","Hot spring entry","Dal bhat lunch in Jhinu village","Jeep transfer to and from the Ghandruk trailhead"],goodToKnow:"The staircase down to the river is steep and comes back up the same way after the soak. Pools are communal and simple; bring modest swimwear and expect trekking traffic in high season.",whatThisIsNot:"This is not a drive-up dip: the springs sit a steep staircase below the village, and everyone in the pool paid for it in leg work.",meetPoint:"Ghandruk jeep stand",fitness:"active",operatorId:"op-heritage",bestMonths:"Oct–Apr",palette:"dawn",lat:28.35,lng:83.82},{slug:"ilam-tea-gardens",name:"Ilam tea garden day",location:"Ilam, eastern hills",category:"culture",world:"calm",duration:"Full day",priceFromNpr:5500,blurb:"A day inside Nepal's tea country: a plucking hour between the hedges, the warm grass smell of a rolling floor, and a first-flush tasting with the maker.",story:"Ilam grows Nepal's best-known tea on ridges that face Darjeeling across the border, and this day walks you through the leaf's whole life. You start between the clipped hedges with a basket and a plucker's quick lesson: two leaves and a bud, again and again. Then the factory, where the rolling floor smells of warm cut grass and the withering troughs breathe out overnight moisture. It ends in the tasting room, slurping first flush from white bowls while the factory manager talks seasons.",includes:["Pickup from Bhadrapur and return","Plucking hour in the garden with a field guide","Factory floor tour with the maker","Guided first-flush tasting"],goodToKnow:"It is a long, winding drive up from the Bhadrapur plains; motion sickness tablets are not a bad idea. Factory processing depends on the day's leaf, so what you see running varies.",whatThisIsNot:"This is not a plantation postcard staged for visitors: it is a working garden and factory, and the machines, schedules and mud take precedence over photographs.",meetPoint:"Bhadrapur airport pickup",fitness:"any",operatorId:"op-heritage",bestMonths:"Mar–Nov (plucking seasons)",palette:"forest",lat:26.91,lng:87.93},{slug:"nuwakot-farm-stay",name:"Nuwakot farm stay",location:"Nuwakot, Trishuli valley",category:"culture",world:"calm",duration:"2 days",priceFromNpr:8500,blurb:"Live below the seven-storey palace on a farm that still works: morning milking, mustard fields, and a dal bhat you had a hand in growing.",story:"Nuwakot's hilltop bazaar sits under the Saat Tale Durbar, the seven-storey palace Prithvi Narayan Shah used while taking Kathmandu, and the farms below it never stopped working. You stay with a farming family: the buffalo is milked before tea, the mustard fields want weeding, and dinner is dal bhat traced to its plots, the saag cut while the rice cooks. Evenings are the bazaar's slow hour, card games and children under the palace walls. The work is optional in theory and irresistible in practice.",includes:["Family homestay room and all meals","Farm mornings: milking, weeding, kitchen garden","Walk up to the seven-storey palace and old bazaar","Dal bhat cooked on the family hearth"],goodToKnow:"Rooms are farmhouse-plain, the bathroom is shared and the toilet may be a squat; power cuts happen. Come willing to be put to light work, that is the stay.",whatThisIsNot:"This is not an agritourism performance: the buffalo needs milking whether you are charming or not, and the family's day does not bend around yours.",meetPoint:"Nuwakot bazaar",fitness:"any",operatorId:"op-heritage",bestMonths:"Oct–Apr",palette:"day",lat:27.91,lng:85.16},{slug:"astronomy-stargazing-night",name:"Himalayan stargazing night",location:"Nagarkot ridge, Kathmandu Valley rim",category:"scenic",world:"calm",duration:"Overnight",priceFromNpr:7500,blurb:"A ridge camp above the valley glow where winter air does the focusing: the Milky Way overhead, mountains pale under starlight, and a telescope host who knows the sky.",story:"Nagarkot's ridge stands high enough above the Kathmandu basin that the city becomes a dim amber pool below, and on moonless winter nights the sky does the rest. Your host sets up the telescope while dinner cooks on the camp stove, then works the night: naked-eye constellations first, Orion climbing over the Himalaya, then the eyepiece for clusters and, when they are up, planets. The cold is part of the instrument: it stills the air. You sleep in a tent and wake for the dawn line on the peaks.",includes:["Ridge camp: tent, warm sleeping bag and dinner","Guided telescope session with your host","Hot drinks through the night","Sunrise over the Himalaya before the drive down"],goodToKnow:"Nights on the rim in season sit near or below freezing; bring every layer you own and we supply the sleeping bag. Dates follow the new moon, and cloud can cancel at short notice.",whatThisIsNot:"This is not a planetarium show: cloud, moonlight and cold call the shots, and a cancelled night rebooked for clearer air is part of how real stargazing works.",meetPoint:"Nagarkot tower road",fitness:"any",operatorId:"op-heritage",bestMonths:"Nov–Feb (driest, darkest skies)",palette:"night",lat:27.72,lng:85.52},{slug:"kathmandu-rim-mtb",name:"Kathmandu rim mountain biking",location:"Shivapuri rim, Kathmandu Valley",category:"adventure",world:"stone",duration:"Full day",priceFromNpr:7500,blurb:"The classic valley escape: climb over Shivapuri's shoulder on jeep road, then let pine-needle singletrack pour you back down to Budhanilkantha with Kathmandu spread out below.",story:"Kathmandu keeps its best riding on its rim. From Budhanilkantha you climb jeep road into Shivapuri National Park, langurs crashing through the oaks overhead, until the valley haze drops away behind you. The reward is the descent: pine-needle singletrack and loose switchbacks that pour you back down towards the sleeping Vishnu statue at Budhanilkantha temple. Hire bikes are proper Scott and Trek hardtails with hydraulic brakes, and the guide sets a pace that keeps the group together.",includes:["Scott or Trek hardtail hire, helmet and gloves","Riding guide and trailside repairs","Shivapuri National Park entry fee","Lunch stop at a ridge teahouse"],goodToKnow:"Bring your passport for the national park gate, and know that the first half of the day is nearly all climbing; e-bike upgrades exist for a reason.",whatThisIsNot:"This is not a lift-served trail centre: every metre of singletrack is earned on the climb, and the lower trails are shared with villagers, dogs and the odd motorbike.",meetPoint:"Budhanilkantha trailhead",fitness:"active",operatorId:"op-annapurna",bestMonths:"Oct–Apr",palette:"forest",lat:27.77,lng:85.38},{slug:"upper-mustang-mtb",name:"Upper Mustang mountain biking",location:"Kagbeni to Lo Manthang, Upper Mustang",category:"adventure",world:"stone",duration:"8 days",priceFromNpr:285e3,blurb:"Ride into the walled kingdom: wind-carved canyons, whitewashed villages and the trans-Himalayan desert road to Lo Manthang, in the rain shadow where Nepal stays dry.",story:"North of Kagbeni the country turns to ochre canyon and wind, and the riding turns ancient: jeep road and salt-trade trail up the Kali Gandaki, nights in whitewashed villages like Chele and Charang, prayer walls to lean the bikes on. Lo Manthang arrives as a walled city on a plain at about 3,800 metres, with a rest-day ride out to the cave dwellings at Chhoser. A support jeep carries bags, spares and anyone who needs an hour off the bike.",includes:["Support jeep with mechanic, spares and bag transfer","Upper Mustang restricted-area permit and ACAP entry, arranged and included","Riding guide and lodge accommodation throughout","Pokhara to Jomsom transfers, both ways"],goodToKnow:"Upper Mustang is a restricted area: the permit alone is about NPR 68,000 for ten days and is folded into the price, along with the NPR 3,000 ACAP entry, and solo permits are not issued. The rain shadow keeps it rideable through the monsoon; the afternoon wind is the tax.",whatThisIsNot:"This is not a bike park: Mustang is wind, washboard and altitude, and the support jeep exists because people use it.",meetPoint:"Jomsom airstrip",fitness:"fit",operatorId:"op-expedition",badges:["restricted"],bestMonths:"May–Oct",palette:"alpenglow",lat:29.18,lng:83.96},{slug:"annapurna-mtb-descent",name:"Annapurna jeep-road descent",location:"Muktinath to Tatopani, Mustang",category:"adventure",world:"stone",duration:"2 days",priceFromNpr:24e3,blurb:"Shuttle high, brake late: from the shrine at Muktinath the switchbacks drop through the world's deepest gorge to the hot springs at Tatopani, and gravity pays for everything.",story:"A jeep lifts you and the bikes to Muktinath, where pilgrims queue for the 108 water spouts at about 3,800 metres. Then you point the front wheel down. Day one drops through Jharkot's ochre fort village and medieval Kagbeni to Jomsom on the river flats; day two follows the Kali Gandaki between Dhaulagiri and Annapurna, an 8,000 metre summit on either side of the deepest gorge on earth, and ends with your shoulders in the hot springs at Tatopani.",includes:["Full-suspension bike hire, helmet, gloves and pads","Jeep shuttle to Muktinath and vehicle backup","Riding guide and a night in a Jomsom lodge","ACAP entry permit"],goodToKnow:"The road is public: jeeps, dust and a headwind that funnels up the gorge from late morning, so the days start early. Winter rides are cold up top and perfect lower down.",whatThisIsNot:"This is not smooth flow trail: it is a working jeep road of washboard, loose rock and blind corners, and your hands will be as tired as your legs.",meetPoint:"Jomsom airstrip",fitness:"fit",operatorId:"op-annapurna",bestMonths:"Oct–Apr",palette:"alpenglow",lat:28.82,lng:83.87},{slug:"mustang-motorbike-tour",name:"Mustang motorbike tour",location:"Pokhara to Muktinath and Kagbeni, Mustang",category:"adventure",world:"stone",duration:"6 days",priceFromNpr:145e3,blurb:"Royal Enfields up the Kali Gandaki: from Pokhara's lakes to Muktinath's shrine and the Kagbeni checkpost where the restricted kingdom of Lo begins, mechanic in tow.",story:"You ride Royal Enfield Himalayans out of Pokhara and up the great trench of the Kali Gandaki: tarmac to Beni, then rock, sand and river fords through Tatopani and Marpha, where lodges pour brandy from their own apple orchards. The route tops out at Muktinath and the windy checkpost at Kagbeni, the edge of restricted Upper Mustang, before turning for home. A mechanic follows in the chase jeep with fuel, spares and your bags; your job is the riding.",includes:["Royal Enfield Himalayan hire and fuel","Chase jeep with mechanic, spares and luggage","Ride leader, lodge stays and ACAP permit"],goodToKnow:"You need a licence valid for motorbikes in Nepal and honest off-tarmac experience: above Beni the road is rough and the wind gets up by noon. Rain-shadow geography keeps the upper valley rideable through the monsoon, when the rest of Nepal is mud.",whatThisIsNot:"This is not a highway cruise: the surface above Beni changes by the kilometre, a dropped bike on washboard is a normal day, and saddle time matters more than top speed.",meetPoint:"Pokhara Lakeside office",fitness:"active",operatorId:"op-expedition",bestMonths:"May–Oct",palette:"alpenglow",lat:28.82,lng:83.87},{slug:"hattiban-rock-climbing",name:"Hattiban rock climbing",location:"Hattiban crag, above Pharping",category:"adventure",world:"stone",duration:"Half day",priceFromNpr:4500,blurb:"Real rock an hour from Thamel: a bolted limestone crag in the pines above Pharping, with lines from first-timer slabs to overhangs that spit out the confident.",story:"Hattiban is where Kathmandu's climbers spend their Saturdays: a south-facing limestone wall in the pine forest above Pharping, bolted with routes from 5a to 7b so first-timers and strong climbers share the same crag. Instructors rig the top ropes, teach the figure-eight and belay every climb, and the harder line one metre to your left keeps talking you into one more go. Between climbs, the horns of Pharping's monasteries drift up through the trees.",includes:["Harness, rock shoes, helmet and all ropes","Qualified instructor and belayer","Top ropes rigged on graded, bolted lines"],goodToKnow:"No experience needed for the easier slabs, and rock shoes in common sizes are part of the kit. The wall takes sun from mid-morning, so winter climbs well and warm months mean an early start.",whatThisIsNot:"This is not an indoor wall: the limestone is sharp, the popular holds are polished glassy, and your forearms will surrender before the morning does.",meetPoint:"Pharping bazaar",fitness:"active",operatorId:"op-annapurna",bestMonths:"Oct–Apr",palette:"forest",lat:27.63,lng:85.26},{slug:"bimal-nagar-climbing",name:"Bimal Nagar climbing",location:"Bimal Nagar, Prithvi Highway near Bandipur",category:"adventure",world:"stone",duration:"Full day",priceFromNpr:5500,blurb:"Long limestone slabs rising straight off the Prithvi Highway: friction, footwork and truck horns below, with Bandipur's ridge-top bazaar waiting for the evening.",story:"Bimal Nagar is the odd one out among Nepal's crags: a serious limestone face standing directly above the Kathmandu to Pokhara highway, roughly halfway between the two cities. The slabs run long and clean, up to 30 metres of pure friction where footwork beats biceps, and bolted multi-pitch lines continue above for anyone hungry for exposure. Most climbers do the day here, then ride forty minutes uphill to sleep in Bandipur, the preserved Newari trading town on the ridge.",includes:["All hardware, harness, shoes and helmet","Instructor-belayed top ropes, lead options for the experienced","Lunch at the highway teahouse below the crag"],goodToKnow:"You climb to an audience: bus passengers, fruit sellers and the whole highway watch the wall. Combine it with a night in Bandipur, because the crag itself has no accommodation.",whatThisIsNot:"This is not a quiet mountain crag: trucks brake for the corner below all day, and the soundtrack is horns, not birdsong.",meetPoint:"Bimal Nagar highway stop",fitness:"active",operatorId:"op-annapurna",bestMonths:"Oct–Apr",palette:"day",lat:27.95,lng:84.43},{slug:"siddha-gufa-caving",name:"Siddha Gufa caving",location:"Siddha Gufa, below Bandipur",category:"adventure",world:"stone",duration:"Half day",priceFromNpr:3e3,blurb:"Nepal's largest cave opens in the hillside below Bandipur: a cathedral chamber of stalactites, horseshoe bats and, when the headlamps click off together, the thickest dark you will ever stand in.",story:"A stepped forest path drops for about forty minutes from Bandipur to a modest mouth in the hillside, which opens into the largest cave chamber in the country. Headlamps pick out melted-looking flowstone, a shifting ceiling of horseshoe bats and the small Shiva shrine that earns the cave its name. The guide knows where the easy floor ends and the slick scrambles begin, and calls the lights-out moment at the heart of the chamber, where the dark is total.",includes:["Headlamps and helmets","Local caving guide","Cave entry ticket"],goodToKnow:"The path down is steep and the cave floor is wet clay, so shoes with grip matter more than anything else you pack. It stays cool inside whatever the season.",whatThisIsNot:"This is not a floodlit show cave: light is whatever you carry, the clay gets on everything, and the bats fly close enough to fan your face.",meetPoint:"Bandipur bazaar",fitness:"any",operatorId:"op-annapurna",bestMonths:"Oct–Apr",palette:"forest",lat:27.94,lng:84.42},{slug:"pokhara-caves-day",name:"Pokhara caves day",location:"Batulechaur and Chhorepatan, Pokhara",category:"adventure",world:"stone",duration:"Half day",priceFromNpr:2800,blurb:"Pokhara from underneath: Mahendra cave's shrine, the Bat Cave's shoulder-width exit squeeze for the brave, then Gupteshwor's chamber where Devi's Falls hammers past underground.",story:"Pokhara sits on limestone, and this outing goes under it. Mahendra cave comes first, easy walkways to a Shiva shrine, then the Bat Cave next door, where horseshoe bats carpet the ceiling and the sporting exit is a body-length squeeze you climb up through while the guide spots you; the front door remains for everyone else. Across town at Chhorepatan, Gupteshwor cave descends behind Devi's Falls to a wet chamber where the river you just watched vanish roars past in the dark.",includes:["Local guide and entry tickets for all three caves","Headlamps for the Bat Cave","Transport between Batulechaur and Chhorepatan"],goodToKnow:"The Bat Cave squeeze is optional and unkind to broad shoulders and bad knees; the door works fine. Gupteshwor's lower chamber closes when the river runs too high after heavy rain.",whatThisIsNot:"This is not wild caving: these are busy, concreted town caves with ticket booths and school groups, and the squeeze is the only real test of the day.",meetPoint:"Chhorepatan, Pokhara",fitness:"any",operatorId:"op-annapurna",bestMonths:"Oct–Apr",palette:"day",lat:28.24,lng:83.98},{slug:"kathmandu-trail-running",name:"Kathmandu valley trail running",location:"Champadevi and Shivapuri ridges, Kathmandu Valley",category:"adventure",world:"stone",duration:"Half day",priceFromNpr:4e3,blurb:"Run above the smog line with someone who races these hills: pine-shaded ridgeline trails on Champadevi or Shivapuri, a stupa on the summit and milk tea at the bottom.",story:"Kathmandu has a proper trail-running scene and this is the shortcut into it: a guided morning on the valley rim with a runner who races the local calendar. South side means Champadevi, a ridge of pine and rhododendron topped by a small stupa; north means Shivapuri's forest trails above Budhanilkantha. Routes stretch from 15 to 25 km depending on your legs, the pace stays conversational unless you ask otherwise, and your guide knows every spring, shortcut and chiya shack on the hill.",includes:["Guide who races Nepal's trail calendar","Route options from 15 to 25 km","Water and snack stops planned in","Post-run milk tea included"],goodToKnow:"This is a run, not a hike with jogging: expect long climbs on rough ground, and bring shoes with lugs. Winter mornings are the clearest; spring haze rewards a dawn start.",whatThisIsNot:"This is not a flat park loop: both ridges deal in steep, rooty climbing, and walking the sharpest pitches is what the locals do too.",meetPoint:"Budhanilkantha trailhead",fitness:"fit",operatorId:"op-annapurna",bestMonths:"Oct–Apr",palette:"forest",lat:27.77,lng:85.38},{slug:"gokarna-forest-golf",name:"Gokarna Forest golf",location:"Gokarna Forest, Kathmandu",category:"scenic",world:"stone",duration:"Full day",priceFromNpr:11500,blurb:"Eighteen holes threaded through a former royal hunting forest on Kathmandu's edge, where spotted deer cross the fairways and the monkeys hold firm opinions about your ball.",story:"Nepal's kings kept this forest for hunting; golfers inherited it. The par-72 course threads old sal and pine, tight and green, with spotted deer grazing the rough and langurs auditing the greens, and on clear winter mornings the Himalaya shows above the treeline. A caddie who knows every borrow walks the round with you, the hire clubs are respectable, and the clubhouse veranda afterwards is where the back nine gets argued about.",includes:["Green fees for 18 holes","Club, shoe and trolley hire","Caddie for the round","Clubhouse lunch"],goodToKnow:"Caddies are how the club works and their local knowledge is worth strokes; winter Saturday tee times book out. The monkeys really do take balls, so play a provisional and keep snacks zipped.",whatThisIsNot:"This is not a windswept links: the fairways are tree-lined and narrow, and the forest collects a steady toll of wayward drives.",meetPoint:"Gokarna clubhouse",fitness:"any",operatorId:"op-annapurna",bestMonths:"Oct–Apr",palette:"forest",lat:27.72,lng:85.4},{slug:"himalayan-golf-pokhara",name:"Himalayan Golf, Pokhara",location:"Bijayapur gorge, Pokhara",category:"scenic",world:"stone",duration:"Full day",priceFromNpr:9500,blurb:"Tee off on the canyon rim, play the round on the floor below: a course carved into a river gorge with the Annapurnas overhead and an island green waiting to ruin your card.",story:"A retired British Army Gurkha officer spent years carving this course into the Bijayapur river gorge east of Pokhara, and nothing else in golf plays quite like it: you drive off the rim onto fairways along the canyon floor, cliff walls on both sides and Machapuchare filling the sky upstream. The signature par 5 finishes on an island green moated by the river, reachable in two only on paper. The walk back out of the gorge is the real closing hole.",includes:["Green fees for 18 holes and club hire","Caddie for the round","Pickup from Lakeside"],goodToKnow:"It is real golf with rough edges: uneven lies, river carries and a steep climb out of the canyon at the end. Play early for the clearest view of the mountain wall.",whatThisIsNot:"This is not a manicured resort course: the gorge sets the rules, the river keeps the balls you feed it, and the clubhouse comforts are basic.",meetPoint:"Pokhara Lakeside office",fitness:"any",operatorId:"op-annapurna",bestMonths:"Oct–Apr",palette:"day",lat:28.18,lng:84.02},{slug:"honey-hunting-demonstration",name:"Honey hunting demonstration",location:"Gurung villages, Lamjung",category:"adventure",world:"stone",duration:"2 days",priceFromNpr:18500,blurb:"From across the gorge you watch Gurung hunters descend a woven bamboo ladder to smoking cliff hives, a harvest the village runs on its own calendar, not yours.",story:"The world's largest honeybee, Apis laboriosa, builds crescent combs under cliff overhangs in the Annapurna foothills, and a handful of Gurung villages hold hereditary rights to harvest them. You jeep and walk in from Besisahar, sleep in a homestay, and at first light watch the hunters descend a hand-plaited bamboo rope ladder, working smoke and a long tango pole to cut comb into a lowered basket. You watch from across the gorge; the honey, the risk and the decision all belong to the village.",includes:["Homestay night and village meals","Community fee paid directly to the village committee","Guide translating the hunters' running commentary","Jeep from Besisahar and the walk-in"],goodToKnow:"Cliff-bee colonies are in decline and staged hunts for tourists have harmed them elsewhere, so we book only villages that set their own quota and season and would be harvesting that week regardless. Dates follow the combs and the weather, not your itinerary, and can shift at short notice.",whatThisIsNot:"This is not a show that runs on demand: if the elders judge the combs thin or the wind wrong, the harvest waits and you go home with photographs of a ladder. Nobody hurries dangerous work for a camera, and we would not book a village that did.",meetPoint:"Besisahar jeep stand",fitness:"active",operatorId:"op-annapurna",badges:["ethical-watch"],bestMonths:"Apr–May · Oct–Nov",palette:"forest",lat:28.3,lng:84.4}];function o(e){return!!(e.story&&e.highlights?.length&&e.profile?.length&&e.itinerary?.length&&e.route?.length&&e.nameNe&&e.kitSlug&&void 0!==e.priceFromNpr&&void 0!==e.rating&&void 0!==e.reviews&&void 0!==e.fairnessDeltaPct)}let r=a.filter(o),n=new Set;for(let e of[...a.map(e=>`trek:${e.slug}`),...t.map(e=>`activity:${e.slug}`)]){if(n.has(e))throw Error(`Duplicate catalog slug: ${e}`);n.add(e)}e.s(["ALL_ACTIVITIES",0,t,"ALL_TREKS",0,a,"FULL_TREKS",0,r,"getFullTrek",0,e=>r.find(a=>a.slug===e),"getTrekAnywhere",0,e=>a.find(a=>a.slug===e),"isFullTrek",0,o],95340)}]);